import { MediaItem, User, Plan, AppSettings, WatchHistoryItem, UserProfile, Ad, Genre, Notification } from './types';
import { SEED_LIBRARY, SEED_PLANS, SEED_USER, SEED_USERS_LIST, SEED_GENRES, SEED_ADS } from './constants';

// Keys for LocalStorage
const KEYS = {
  LIBRARY: 'xp_library',
  USER: 'xp_user', // Current logged in account
  ACTIVE_PROFILE_ID: 'xp_active_profile_id',
  USERS_LIST: 'xp_users_list', // All users (Admin db)
  PLANS: 'xp_plans',
  SETTINGS: 'xp_settings',
  GENRES: 'xp_genres',
  ADS: 'xp_ads' // Business ads + System ads
};

const loadData = <T>(key: string, seed: T): T => {
  const stored = localStorage.getItem(key);
  if (stored) {
    try {
      return JSON.parse(stored);
    } catch (e) {
      console.error(`Error parsing ${key}`, e);
    }
  }
  return seed;
};

const saveData = (key: string, data: any) => {
  localStorage.setItem(key, JSON.stringify(data));
};

// Update Seed Settings for Kada+
const KADA_SEED_SETTINGS: AppSettings = {
  ...SEED_SETTINGS,
  appName: 'Kada+',
  appLogoText: 'Kada',
  appLogoHighlight: '+',
};

export const store = {
  // --- LIBRARY ---
  getLibrary: (): MediaItem[] => loadData(KEYS.LIBRARY, SEED_LIBRARY),

  saveLibrary: (items: MediaItem[]) => {
    saveData(KEYS.LIBRARY, items);
    window.dispatchEvent(new Event('storage_library'));
  },

  // --- GENRES ---
  getGenres: (): Genre[] => loadData(KEYS.GENRES, SEED_GENRES),
  saveGenres: (genres: Genre[]) => {
    saveData(KEYS.GENRES, genres);
    window.dispatchEvent(new Event('storage_genres'));
  },

  // --- ADS (Business & System) ---
  getAds: (): Ad[] => loadData(KEYS.ADS, SEED_ADS),
  saveAds: (ads: Ad[]) => {
    saveData(KEYS.ADS, ads);
    window.dispatchEvent(new Event('storage_ads'));
  },
  addBusinessAd: (ad: Ad) => {
    const ads = store.getAds();
    ads.push(ad);
    store.saveAds(ads);
  },

  // --- USER ACCOUNT & AUTH ---
  getAllUsers: (): User[] => loadData(KEYS.USERS_LIST, SEED_USERS_LIST),

  saveAllUsers: (users: User[]) => {
    saveData(KEYS.USERS_LIST, users);
    window.dispatchEvent(new Event('storage_users_list'));
  },

  getUser: (): User => loadData(KEYS.USER, SEED_USER),

  saveUser: (user: User) => {
    saveData(KEYS.USER, user);
    // Also update the user in the USERS_LIST if they exist there
    const allUsers = store.getAllUsers();
    const idx = allUsers.findIndex(u => u.id === user.id);
    if (idx !== -1) {
      allUsers[idx] = user;
    } else {
      allUsers.push(user);
    }
    store.saveAllUsers(allUsers);
    window.dispatchEvent(new Event('storage_user'));
  },

  logout: () => {
    localStorage.removeItem(KEYS.ACTIVE_PROFILE_ID);
  },

  registerUser: (newUser: User) => {
     // Initialize with welcome notification
     newUser.notifications = [
         {
             id: `notif-${Date.now()}`,
             title: 'Welcome to Kada+!',
             message: 'Your account has been successfully created. Start watching now!',
             date: Date.now(),
             isRead: false,
             type: 'success'
         }
     ];
     store.saveUser(newUser);
  },

  // --- NOTIFICATIONS ---
  getNotifications: (): Notification[] => {
      const user = store.getUser();
      return user.notifications || [];
  },

  markNotificationRead: (notifId: string) => {
      const user = store.getUser();
      if (user.notifications) {
          user.notifications = user.notifications.map(n => 
              n.id === notifId ? { ...n, isRead: true } : n
          );
          store.saveUser(user);
      }
  },

  markAllNotificationsRead: () => {
      const user = store.getUser();
      if (user.notifications) {
          user.notifications = user.notifications.map(n => ({ ...n, isRead: true }));
          store.saveUser(user);
      }
  },

  addNotification: (notification: Notification) => {
      const user = store.getUser();
      const currentNotifs = user.notifications || [];
      user.notifications = [notification, ...currentNotifs];
      store.saveUser(user);
  },

  // --- PROFILE MANAGEMENT ---
  getActiveProfileId: (): string | null => localStorage.getItem(KEYS.ACTIVE_PROFILE_ID),

  setActiveProfileId: (id: string) => {
    localStorage.setItem(KEYS.ACTIVE_PROFILE_ID, id);
    window.dispatchEvent(new Event('storage_profile'));
  },

  getCurrentProfile: (): UserProfile => {
    const user = store.getUser();
    const profileId = store.getActiveProfileId();
    // Default to first profile if none selected or invalid
    return user.profiles.find(p => p.id === profileId) || user.profiles[0];
  },

  updateProfile: (updatedProfile: UserProfile) => {
    const user = store.getUser();
    const idx = user.profiles.findIndex(p => p.id === updatedProfile.id);
    if (idx !== -1) {
      user.profiles[idx] = updatedProfile;
      store.saveUser(user);
      window.dispatchEvent(new Event('storage_profile'));
    }
  },

  // --- MY LIST & HISTORY (Per Profile) ---
  addToMyList: (mediaId: string) => {
    const profile = store.getCurrentProfile();
    if (!profile.myList.includes(mediaId)) {
        profile.myList.unshift(mediaId);
        store.updateProfile(profile);
    }
  },

  removeFromMyList: (mediaId: string) => {
    const profile = store.getCurrentProfile();
    profile.myList = profile.myList.filter(id => id !== mediaId);
    store.updateProfile(profile);
  },

  updateWatchHistory: (mediaId: string, timestamp: number, duration: number, episodeId?: string) => {
    const profile = store.getCurrentProfile();
    if (!profile) return; // Guard

    const progress = duration > 0 ? timestamp / duration : 0;

    const existingIdx = profile.watchHistory.findIndex(h => h.mediaId === mediaId && h.episodeId === episodeId);

    const newItem: WatchHistoryItem = {
      mediaId,
      episodeId,
      timestamp,
      progress,
      lastWatchedAt: Date.now()
    };

    if (existingIdx > -1) {
      profile.watchHistory[existingIdx] = newItem;
    } else {
      profile.watchHistory.unshift(newItem);
    }

    // Sort by last watched
    profile.watchHistory.sort((a, b) => b.lastWatchedAt - a.lastWatchedAt);

    // Keep history manageable (e.g. last 50 items)
    if (profile.watchHistory.length > 50) {
      profile.watchHistory = profile.watchHistory.slice(0, 50);
    }

    store.updateProfile(profile);
  },

  // --- PLANS ---
  getPlans: (): Plan[] => loadData(KEYS.PLANS, SEED_PLANS),

  savePlans: (plans: Plan[]) => {
    saveData(KEYS.PLANS, plans);
    window.dispatchEvent(new Event('storage_plans'));
  },

  // --- SETTINGS ---
  getSettings: (): AppSettings => loadData(KEYS.SETTINGS, KADA_SEED_SETTINGS),

  saveSettings: (settings: AppSettings) => {
    saveData(KEYS.SETTINGS, settings);
    window.dispatchEvent(new Event('storage_settings'));
  },

  // Helper to listen to changes
  subscribe: (key: string, callback: () => void) => {
    const eventName = `storage_${key}`;
    window.addEventListener(eventName, callback);
    return () => window.removeEventListener(eventName, callback);
  }
};

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { HomeIcon, SearchIcon, DashboardIcon, UserIcon, CalendarIcon, BellIcon, CheckIcon, CloseIcon } from './Icons';
import { store } from '../store';
import { AppSettings, User, UserProfile, Notification } from '../types';

interface LayoutProps {
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ children }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [scrolled, setScrolled] = useState(false);
  const [settings, setSettings] = useState<AppSettings>(store.getSettings());
  const [user, setUser] = useState<User>(store.getUser());
  const [currentProfile, setCurrentProfile] = useState<UserProfile>(store.getCurrentProfile());

  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const isLanding = location.pathname === '/';
  const isPlayer = location.pathname.startsWith('/watch');
  const isAdmin = location.pathname.startsWith('/admin');
  const isProfileSelect = location.pathname === '/profiles';
  const isAuthPage = location.pathname === '/login' || location.pathname === '/signup';

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);

    const updateData = () => {
        setSettings(store.getSettings());
        const u = store.getUser();
        setUser(u);
        setCurrentProfile(store.getCurrentProfile());
        setNotifications(u.notifications || []);
    };

    updateData();

    const unsubSettings = store.subscribe('settings', updateData);
    const unsubUser = store.subscribe('user', updateData);
    const unsubProfile = store.subscribe('profile', updateData);

    return () => {
      window.removeEventListener('scroll', handleScroll);
      unsubSettings();
      unsubUser();
      unsubProfile();
    };
  }, []);

  useEffect(() => {
      if (!isLanding && !isProfileSelect && !isAuthPage && !store.getActiveProfileId() && user.id) {
          navigate('/profiles');
      }
  }, [location.pathname, user.id]);

  const handleProfileSwitch = (profileId: string) => {
      store.setActiveProfileId(profileId);
      setShowProfileMenu(false);
      navigate('/app');
  };

  const handleMarkRead = (id: string) => {
      store.markNotificationRead(id);
  };

  const handleMarkAllRead = () => {
      store.markAllNotificationsRead();
  };

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const isActive = (path: string) => location.pathname === path ? 'text-kada-pink font-bold' : 'text-gray-300 hover:text-white';

  if (isProfileSelect || isAuthPage) {
      return <>{children}</>;
  }

  return (
    <div className="min-h-screen bg-kada-dark text-white font-sans selection:bg-kada-pink selection:text-white relative overflow-x-hidden">

      {/* Ambient Background Gradient Mesh */}
      {!isPlayer && (
        <div className="fixed inset-0 z-0 pointer-events-none opacity-20">
          <div className="absolute top-[-10%] left-[-10%] w-[50vw] h-[50vw] bg-kada-pink rounded-full blur-[150px] animate-float"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[40vw] h-[40vw] bg-kada-yellow rounded-full blur-[150px] animate-pulse-slow"></div>
        </div>
      )}

      {!isPlayer && !isAdmin && (
        <div className={`fixed top-4 left-0 right-0 z-50 flex justify-center transition-all duration-500 ${scrolled ? 'translate-y-0' : 'translate-y-2'}`}>
          <nav className="glass-panel px-6 py-3 rounded-full flex items-center gap-8 shadow-2xl transition-all duration-300 max-w-5xl w-[95%] sm:w-auto">

            <Link to={isLanding ? '/' : '/app'} className="flex items-center gap-1 group">
              <span className="text-2xl font-black tracking-tighter text-white">
                {settings.appLogoText}<span className="text-transparent bg-clip-text bg-gradient-to-r from-kada-pink to-kada-yellow">{settings.appLogoHighlight}</span>
              </span>
            </Link>

            {!isLanding && (
              <div className="hidden md:flex items-center space-x-6 border-l border-white/10 pl-6 h-6">
                <Link to="/app" className={`text-sm transition-colors ${isActive('/app')}`}>Home</Link>
                <Link to="/browse" className={`text-sm transition-colors ${isActive('/browse')}`}>Explore</Link>
                <Link to="/coming-soon" className={`text-sm transition-colors ${isActive('/coming-soon')}`}>New</Link>
                {user.isAdmin && (
                   <Link to="/admin" className={`text-sm transition-colors ${location.pathname.startsWith('/admin') ? 'text-kada-yellow font-bold' : 'text-gray-300 hover:text-white'}`}>Admin</Link>
                )}
              </div>
            )}

            <div className="flex-1"></div>

            <div className="flex items-center gap-5">
              {isLanding ? (
                 <div className="flex items-center gap-3">
                     <Link to="/login" className="text-sm font-semibold hover:text-kada-pink transition-colors">Log In</Link>
                     <Link to="/signup" className="px-5 py-2 bg-gradient-to-r from-kada-pink to-kada-yellow text-black font-bold text-sm rounded-full hover:shadow-lg hover:shadow-kada-pink/30 transition-all">
                        Join
                     </Link>
                 </div>
              ) : (
                <div className="flex items-center gap-5">
                    <Link to="/browse" className="text-white hover:text-kada-pink transition-colors"><SearchIcon className="w-5 h-5" /></Link>

                    {/* NOTIFICATIONS */}
                    <div className="relative">
                        <button 
                            onClick={() => { setShowNotifications(!showNotifications); setShowProfileMenu(false); }}
                            className="relative text-white hover:text-kada-yellow transition-colors"
                        >
                            <BellIcon className="w-5 h-5" />
                            {unreadCount > 0 && (
                                <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-kada-pink rounded-full border-2 border-black"></span>
                            )}
                        </button>

                        {showNotifications && (
                            <div className="absolute top-full right-[-60px] md:right-0 mt-6 w-80 glass-panel rounded-2xl overflow-hidden z-50 animate-fade-in origin-top-right">
                                <div className="p-4 border-b border-white/10 flex justify-between items-center bg-black/20">
                                    <span className="font-bold text-sm text-white">Notifications</span>
                                    {unreadCount > 0 && (
                                        <button onClick={handleMarkAllRead} className="text-xs text-kada-pink hover:underline">Mark all read</button>
                                    )}
                                </div>
                                <div className="max-h-[300px] overflow-y-auto custom-scrollbar">
                                    {notifications.length === 0 ? (
                                        <div className="p-6 text-center text-gray-400 text-sm">All caught up!</div>
                                    ) : (
                                        notifications.map(notif => (
                                            <div 
                                                key={notif.id} 
                                                onClick={() => handleMarkRead(notif.id)}
                                                className={`p-4 border-b border-white/5 hover:bg-white/5 transition-colors cursor-pointer relative ${!notif.isRead ? 'bg-white/5' : ''}`}
                                            >
                                                {!notif.isRead && <div className="absolute left-0 top-0 bottom-0 w-1 bg-kada-pink"></div>}
                                                <h4 className={`text-sm font-bold mb-1 ${!notif.isRead ? 'text-white' : 'text-gray-400'}`}>{notif.title}</h4>
                                                <p className="text-xs text-gray-500 leading-relaxed">{notif.message}</p>
                                            </div>
                                        ))
                                    )}
                                </div>
                            </div>
                        )}
                    </div>

                    {/* PROFILE */}
                    <div className="relative group">
                        <button 
                            onClick={() => { setShowProfileMenu(!showProfileMenu); setShowNotifications(false); }}
                            className="flex items-center gap-2"
                        >
                            <div className="w-9 h-9 rounded-full bg-zinc-800 p-[2px] bg-gradient-to-tr from-kada-pink to-kada-yellow">
                                <img src={currentProfile.avatarUrl || 'https://picsum.photos/200'} alt={currentProfile.name} className="w-full h-full rounded-full object-cover border-2 border-black" />
                            </div>
                        </button>

                        {showProfileMenu && (
                            <div className="absolute top-full right-0 mt-6 w-56 glass-panel rounded-2xl overflow-hidden z-50 animate-fade-in origin-top-right">
                                <div className="p-3 border-b border-white/10">
                                    {user.profiles.map(p => (
                                        <button 
                                            key={p.id}
                                            onClick={() => handleProfileSwitch(p.id)}
                                            className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg hover:bg-white/10 transition-colors ${p.id === currentProfile.id ? 'bg-white/10' : ''}`}
                                        >
                                            <img src={p.avatarUrl} className="w-8 h-8 rounded-full object-cover" />
                                            <span className={`text-sm ${p.id === currentProfile.id ? 'font-bold text-white' : 'text-gray-400'}`}>{p.name}</span>
                                        </button>
                                    ))}
                                    <Link to="/profiles" className="w-full text-left text-xs text-kada-yellow hover:underline px-3 py-2 mt-2 block">Manage Profiles</Link>
                                </div>
                                <div className="p-2 space-y-1">
                                    <Link to="/profile" className="block px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/5 rounded-lg" onClick={() => setShowProfileMenu(false)}>Account</Link>
                                    <button onClick={() => { store.logout(); navigate('/'); }} className="w-full text-left block px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/5 rounded-lg">Sign Out</button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
              )}
            </div>
          </nav>
        </div>
      )}

      {/* Mobile Bottom Navigation */}
      {!isLanding && !isPlayer && !isAdmin && (
        <div className="md:hidden fixed bottom-6 left-6 right-6 z-50">
           <div className="glass-panel rounded-2xl flex justify-around items-center p-3 shadow-2xl">
              <Link to="/app" className={`flex flex-col items-center p-2 rounded-lg transition-colors ${location.pathname === '/app' ? 'text-kada-pink bg-white/10' : 'text-gray-400'}`}>
                <HomeIcon className="w-6 h-6" />
              </Link>
              <Link to="/browse" className={`flex flex-col items-center p-2 rounded-lg transition-colors ${location.pathname === '/browse' ? 'text-kada-pink bg-white/10' : 'text-gray-400'}`}>
                <SearchIcon className="w-6 h-6" />
              </Link>
              <Link to="/coming-soon" className={`flex flex-col items-center p-2 rounded-lg transition-colors ${location.pathname === '/coming-soon' ? 'text-kada-pink bg-white/10' : 'text-gray-400'}`}>
                <CalendarIcon className="w-6 h-6" />
              </Link>
              <Link to="/profile" className={`flex flex-col items-center p-2 rounded-lg transition-colors ${location.pathname === '/profile' ? 'text-kada-pink bg-white/10' : 'text-gray-400'}`}>
                <UserIcon className="w-6 h-6" />
              </Link>
           </div>
        </div>
      )}

      {/* Main Content */}
      <main className="relative z-10">
        {children}
      </main>

      {/* Footer */}
      {!isPlayer && !isAdmin && !isAuthPage && (
        <footer className="border-t border-white/5 bg-black py-16 relative z-10 mb-20 md:mb-0">
          <div className="container mx-auto px-6 max-w-5xl">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8 text-sm text-gray-500">
              <ul className="space-y-4">
                  <li><Link to="/app" className="hover:text-kada-pink transition-colors">Home</Link></li>
                  <li><Link to="/browse" className="hover:text-kada-pink transition-colors">Browse</Link></li>
                  <li><Link to="/coming-soon" className="hover:text-kada-pink transition-colors">Coming Soon</Link></li>
              </ul>
              <ul className="space-y-4">
                  <li><Link to="/profile" className="hover:text-kada-pink transition-colors">Account</Link></li>
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Help Center</a></li>
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Terms of Use</a></li>
              </ul>
              <ul className="space-y-4">
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Privacy</a></li>
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Cookie Preferences</a></li>
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Corporate Info</a></li>
              </ul>
              <div className="space-y-4">
                  <h4 className="text-white font-bold">Connect</h4>
                  <div className="flex gap-4">
                      <div className="w-8 h-8 rounded-full bg-white/10 hover:bg-kada-pink transition-colors cursor-pointer"></div>
                      <div className="w-8 h-8 rounded-full bg-white/10 hover:bg-kada-yellow transition-colors cursor-pointer"></div>
                      <div className="w-8 h-8 rounded-full bg-white/10 hover:bg-white transition-colors cursor-pointer"></div>
                  </div>
                  <p className="text-xs pt-4">© 2024 Kada+ Nigeria</p>
              </div>
            </div>
          </div>
        </footer>
      )}
    </div>
  );
};

export default Layout;

import React from 'react';
import { Link } from 'react-router-dom';
import { MediaItem } from '../types';
import { PlayIcon, CalendarIcon, LockIcon } from './Icons';

interface MediaCardProps {
  item: MediaItem;
  variant?: 'portrait' | 'landscape';
  progress?: number; // 0 to 1
}

const MediaCard: React.FC<MediaCardProps> = ({ item, variant = 'landscape', progress }) => {
  const isPortrait = variant === 'portrait';
  const aspectRatio = isPortrait ? 'aspect-[2/3]' : 'aspect-video';
  const imageUrl = isPortrait ? (item.posterUrl || item.thumbnailUrl) : item.thumbnailUrl;

  return (
    <Link to={`/title/${item.id}`} className="group relative block h-full">
      <div className={`relative overflow-hidden rounded-2xl ${aspectRatio} bg-zinc-900 border border-white/10 transition-all duration-300 group-hover:shadow-[0_0_20px_rgba(255,0,128,0.3)] group-hover:border-kada-pink/50`}>
        <img
          src={imageUrl}
          alt={item.title}
          className={`h-full w-full object-cover transition-transform duration-700 group-hover:scale-110 ${item.isComingSoon ? 'grayscale opacity-60' : 'opacity-90 group-hover:opacity-100'}`}
          loading="lazy"
        />

        {/* Overlay Gradient */}
        <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-90" />

        {/* Series Badge */}
        {item.type === 'series' && (
           <div className="absolute top-3 right-3 glass-panel text-white text-[9px] font-bold px-2 py-1 rounded-full uppercase tracking-wide border border-white/20">
             Series
           </div>
        )}

        {/* Coming Soon Badge */}
        {item.isComingSoon && (
           <div className="absolute top-3 left-3 bg-white text-black text-[10px] font-bold px-2 py-1 rounded-full flex items-center gap-1 shadow-lg">
             <CalendarIcon className="w-3 h-3" /> COMING SOON
           </div>
        )}

        {/* Play Icon on Hover */}
        {!item.isComingSoon && (
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-300 z-20 backdrop-blur-[2px]">
            <div className="h-12 w-12 rounded-full bg-gradient-to-r from-kada-pink to-kada-yellow flex items-center justify-center shadow-xl transform scale-50 group-hover:scale-100 transition-transform">
               <PlayIcon className="h-5 w-5 fill-black text-black translate-x-0.5" />
            </div>
          </div>
        )}

        {/* Progress Bar for Continue Watching */}
        {progress !== undefined && progress > 0 && (
            <div className="absolute bottom-0 left-0 right-0 h-1 bg-white/20">
                <div className="h-full bg-gradient-to-r from-kada-pink to-kada-yellow" style={{ width: `${progress * 100}%` }}></div>
            </div>
        )}

        {/* Content */}
        <div className="absolute bottom-0 left-0 w-full p-4 z-10">
          <h3 className={`font-bold text-white leading-tight group-hover:text-kada-yellow transition-colors ${isPortrait ? 'text-sm line-clamp-1' : 'text-base line-clamp-1'}`}>
            {item.title}
          </h3>
          <div className="flex items-center gap-2 mt-1">
             <span className="text-[10px] text-kada-pink font-bold border border-kada-pink/30 px-1.5 rounded">{item.rating}</span>
             <span className="text-[10px] text-gray-400">{item.genre}</span>
          </div>
        </div>
      </div>
    </Link>
  );
};

export default MediaCard;

import React, { useEffect, useState, useRef, useMemo } from 'react';
import { Link } from 'react-router-dom';
import MediaCard from '../components/MediaCard';
import { PlayIcon, InfoIcon, TrendingUpIcon, StarIcon, FilmIcon, TvIcon, VolumeMuteIcon, VolumeHighIcon, ClockIcon } from '../components/Icons';
import { store } from '../store';
import { MediaItem, UserProfile, AppSettings } from '../types';

const Home: React.FC = () => {
  const [library, setLibrary] = useState<MediaItem[]>([]);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [settings, setSettings] = useState<AppSettings>(store.getSettings());

  // Hero Slider State
  const [featuredItems, setFeaturedItems] = useState<MediaItem[]>([]);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [showVideo, setShowVideo] = useState(false);
  const [isMuted, setIsMuted] = useState(true);
  const slideInterval = useRef<any>(null);

  useEffect(() => {
    setLibrary(store.getLibrary());
    setProfile(store.getCurrentProfile());
    setSettings(store.getSettings());

    const unsubLibrary = store.subscribe('library', () => setLibrary(store.getLibrary()));
    const unsubProfile = store.subscribe('profile', () => setProfile(store.getCurrentProfile()));
    const unsubSettings = store.subscribe('settings', () => setSettings(store.getSettings()));

    return () => {
      unsubLibrary();
      unsubProfile();
      unsubSettings();
    };
  }, []);

  const simulatedCountry = settings.simulatedCountry || 'US';

  const safeLibrary = useMemo(() => {
    if (!profile) return [];
    return library.filter(item => {
        const kidsCheck = profile.isKids ? item.isKidsSafe : true;
        let geoCheck = true;
        if (item.allowedCountries && item.allowedCountries.length > 0) {
            geoCheck = item.allowedCountries.includes(simulatedCountry);
        }
        return kidsCheck && geoCheck;
    });
  }, [library, profile, simulatedCountry]);

  useEffect(() => {
      if (safeLibrary.length > 0) {
          const featured = safeLibrary.filter(item => item.trending && !item.isComingSoon).slice(0, 5);
          setFeaturedItems(featured.length > 0 ? featured : safeLibrary.slice(0, 5));
      }
  }, [safeLibrary]);

  useEffect(() => {
      if (featuredItems.length <= 1) return;
      const nextSlide = () => {
          setShowVideo(false);
          setCurrentSlide(prev => (prev + 1) % featuredItems.length);
      };
      slideInterval.current = setInterval(nextSlide, 15000);
      return () => { if (slideInterval.current) clearInterval(slideInterval.current); };
  }, [featuredItems]);

  useEffect(() => {
      const timer = setTimeout(() => { setShowVideo(true); }, 3000);
      return () => clearTimeout(timer);
  }, [currentSlide]);

  const activeSlide = featuredItems[currentSlide];

  // Lists
  const trending = safeLibrary.filter(item => item.trending && !item.isComingSoon);
  const popularList = safeLibrary.filter(item => (item.analytics?.listAdds || 0) > 1000 && !item.isComingSoon).sort((a, b) => (b.analytics?.listAdds || 0) - (a.analytics?.listAdds || 0));
  const topMovies = safeLibrary.filter(item => item.type === 'movie' && !item.isComingSoon).sort((a, b) => (b.analytics?.views || 0) - (a.analytics?.views || 0)).slice(0, 10);
  const topSeries = safeLibrary.filter(item => item.type === 'series' && !item.isComingSoon).sort((a, b) => (b.analytics?.views || 0) - (a.analytics?.views || 0)).slice(0, 10);

  const continueWatching = useMemo(() => {
      if (!profile) return [];
      return profile.watchHistory.map(h => {
        const item = safeLibrary.find(m => m.id === h.mediaId);
        if (!item) return null;
        return { item, history: h };
      }).filter(x => x !== null && x.history.progress < 0.95).slice(0, 4);
  }, [profile, safeLibrary]);

  const myListItems = useMemo(() => {
      if (!profile) return [];
      return profile.myList.map(id => safeLibrary.find(m => m.id === id)).filter(Boolean) as MediaItem[];
  }, [profile, safeLibrary]);

  if (!profile) return null; 
  if (featuredItems.length === 0) return (
      <div className="h-screen flex items-center justify-center text-white bg-black">
          <p>No content available.</p>
      </div>
  );

  return (
    <div className="pb-20">

      {/* Glass Hero Section */}
      <div className="relative w-full h-[95vh] overflow-hidden flex items-center justify-center">
        {/* Background Video/Image */}
        <div className="absolute inset-0 z-0">
             {showVideo && activeSlide.trailerUrl ? (
                 <video 
                    src={activeSlide.trailerUrl}
                    className="w-full h-full object-cover scale-105"
                    autoPlay
                    muted={isMuted}
                    loop
                    playsInline
                 />
             ) : (
                 <img 
                    src={activeSlide.backdropUrl || activeSlide.thumbnailUrl} 
                    alt={activeSlide.title}
                    className="w-full h-full object-cover animate-pulse-slow"
                 />
             )}
             <div className="absolute inset-0 bg-black/40"></div>
             <div className="absolute inset-0 bg-gradient-to-t from-kada-dark via-transparent to-transparent"></div>
             <div className="absolute inset-0 bg-gradient-to-r from-kada-dark/80 via-transparent to-kada-dark/80"></div>
        </div>

        {/* Floating Glass Content Card */}
        <div className="relative z-10 max-w-5xl w-full px-6 flex flex-col md:flex-row items-center gap-10 mt-20">
            {/* Left: Text Content */}
            <div className="flex-1 space-y-6 text-center md:text-left">
                 <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full border border-white/20 bg-black/30 backdrop-blur-md">
                    <span className="w-2 h-2 rounded-full bg-kada-pink animate-pulse"></span>
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Featured Premiere</span>
                 </div>

                 <h1 className="text-5xl md:text-7xl lg:text-8xl font-black text-transparent bg-clip-text bg-gradient-to-br from-white via-white to-gray-400 drop-shadow-2xl leading-none">
                     {activeSlide.title}
                 </h1>

                 <div className="flex flex-wrap items-center justify-center md:justify-start gap-4 text-sm font-semibold text-gray-300">
                     <span className="text-kada-yellow">{activeSlide.year}</span>
                     <span className="w-1 h-1 rounded-full bg-gray-500"></span>
                     <span>{activeSlide.genre}</span>
                     <span className="w-1 h-1 rounded-full bg-gray-500"></span>
                     <span className="border border-gray-500 px-2 rounded">{activeSlide.rating}</span>
                 </div>

                 <p className="text-lg text-gray-200 line-clamp-3 md:line-clamp-none max-w-xl mx-auto md:mx-0 drop-shadow-lg">
                     {activeSlide.description}
                 </p>

                 <div className="flex items-center justify-center md:justify-start gap-4 pt-4">
                     <Link 
                        to={`/watch/${activeSlide.id}`}
                        className="group relative px-8 py-4 bg-white text-black rounded-full font-bold text-lg overflow-hidden shadow-[0_0_20px_rgba(255,255,255,0.3)] transition-all hover:scale-105"
                     >
                         <div className="absolute inset-0 bg-gradient-to-r from-kada-pink to-kada-yellow opacity-0 group-hover:opacity-100 transition-opacity"></div>
                         <div className="relative flex items-center gap-2 group-hover:text-white transition-colors">
                            <PlayIcon className="w-6 h-6 fill-current" /> <span>Watch Now</span>
                         </div>
                     </Link>
                     <Link 
                        to={`/title/${activeSlide.id}`}
                        className="px-8 py-4 glass-panel rounded-full font-bold text-lg hover:bg-white/10 transition-all flex items-center gap-2 border border-white/20"
                     >
                         <InfoIcon className="w-6 h-6" /> Details
                     </Link>
                 </div>
            </div>

            {/* Right: Glass Card Preview (Hidden on mobile) */}
            <div className="hidden md:block w-80 lg:w-96 aspect-[2/3] relative group">
                <div className="absolute inset-0 bg-gradient-to-tr from-kada-pink to-kada-yellow rounded-2xl blur-lg opacity-40 group-hover:opacity-60 transition-opacity"></div>
                <div className="relative h-full w-full rounded-2xl overflow-hidden border border-white/20 shadow-2xl">
                    <img src={activeSlide.posterUrl || activeSlide.thumbnailUrl} className="w-full h-full object-cover" />
                </div>
                {/* Floating Mute Button */}
                {showVideo && (
                    <button 
                        onClick={() => setIsMuted(!isMuted)}
                        className="absolute bottom-4 right-4 w-10 h-10 rounded-full glass-panel flex items-center justify-center hover:bg-white/20 transition-colors"
                    >
                        {isMuted ? <VolumeMuteIcon className="w-5 h-5 text-white" /> : <VolumeHighIcon className="w-5 h-5 text-white" />}
                    </button>
                )}
            </div>
        </div>

        {/* Slide Indicators */}
        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex gap-2 z-20">
            {featuredItems.map((_, idx) => (
                <button 
                    key={idx}
                    onClick={() => { setCurrentSlide(idx); setShowVideo(false); }}
                    className={`h-1.5 rounded-full transition-all duration-300 ${currentSlide === idx ? 'w-8 bg-white shadow-[0_0_10px_rgba(255,255,255,0.8)]' : 'w-2 bg-white/30 hover:bg-white/60'}`}
                />
            ))}
        </div>
      </div>

      {/* Content Section */}
      <div className="container mx-auto px-6 relative z-10 -mt-10 space-y-16">

        {/* Continue Watching - High Priority */}
        {continueWatching.length > 0 && (
           <section>
             <div className="flex items-center gap-3 mb-6">
                <div className="p-2 rounded-full bg-white/10 text-kada-pink"><ClockIcon className="w-5 h-5" /></div>
                <h2 className="text-2xl font-bold text-white tracking-tight">Continue Watching</h2>
             </div>
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                {continueWatching.map(({ item, history }) => (
                   <div key={`${item!.id}-${history.episodeId || ''}`} className="relative group">
                      <MediaCard item={item!} progress={history.progress} />
                   </div>
                ))}
             </div>
           </section>
        )}

        {/* Top 10 Stylized Row */}
        {topMovies.length > 0 && (
            <section>
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 rounded-full bg-white/10 text-kada-yellow"><StarIcon className="w-5 h-5" /></div>
                    <h2 className="text-2xl font-bold text-white tracking-tight">Top 10 Movies</h2>
                </div>
                <div className="flex overflow-x-auto gap-8 pb-8 no-scrollbar pl-4 items-center">
                    {topMovies.map((item, index) => (
                        <div key={item.id} className="flex-shrink-0 relative group flex items-end">
                            <span className="text-[120px] font-black text-transparent bg-clip-text bg-gradient-to-b from-gray-700 to-transparent leading-none -mr-10 z-0 scale-y-110 translate-y-4 font-outline-2">{index + 1}</span>
                            <div className="w-40 z-10 transition-transform duration-300 group-hover:-translate-y-4">
                               <MediaCard item={item} variant="portrait" />
                            </div>
                        </div>
                    ))}
                </div>
            </section>
        )}

        {/* Categories */}
        {[
            { title: "Trending Now", icon: TrendingUpIcon, items: trending, color: "text-kada-pink" },
            { title: "My List", icon: ListIcon, items: myListItems, color: "text-white" },
            { title: "Blockbuster Movies", icon: FilmIcon, items: safeLibrary.filter(i => i.type === 'movie' && !i.isComingSoon), color: "text-blue-400" },
            { title: "Binge-Worthy Series", icon: TvIcon, items: safeLibrary.filter(i => i.type === 'series' && !i.isComingSoon), color: "text-purple-400" },
        ].map(cat => cat.items.length > 0 && (
            <section key={cat.title}>
               <div className="flex items-center gap-3 mb-6">
                   <div className={`p-2 rounded-full bg-white/10 ${cat.color}`}>
                       {React.createElement(cat.icon, { className: "w-5 h-5" })}
                   </div>
                   <h2 className="text-2xl font-bold text-white tracking-tight">{cat.title}</h2>
               </div>
               <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                 {cat.items.slice(0, 5).map(item => (
                   <MediaCard key={item.id} item={item} variant="portrait" />
                 ))}
               </div>
            </section>
        ))}

      </div>

      {/* Custom CSS for Text Outline effect used in Top 10 */}
      <style>{`
        .font-outline-2 {
            -webkit-text-stroke: 2px rgba(255,255,255,0.2);
        }
        .text-kada-pink { color: #ff0080; }
        .text-kada-yellow { color: #ffcc00; }
      `}</style>
    </div>
  );
};

// Simple Icon wrapper for List
const ListIcon: React.FC<{className?: string}> = ({className}) => (
    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className={className}>
      <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 5.25h16.5m-16.5 4.5h16.5m-16.5 4.5h16.5m-16.5 4.5h16.5" />
    </svg>
);

export default Home;

