        {/* SERIES BANNER AD */}
        <div className="w-full aspect-[21/9] md:aspect-[5/1] rounded-xl overflow-hidden relative mt-12 mb-20 border border-white/10">
             <div className="absolute inset-0 bg-gradient-to-r from-red-900 to-black"></div>
             <div className="absolute inset-0 flex items-center p-8 md:p-12">
                 <div className="flex-1">
                     <h3 className="text-3xl font-black text-white mb-2 uppercase italic tracking-tighter">Action Pack Weekend</h3>
                     <p className="text-gray-300 max-w-md">Stream all your favorite action movies back-to-back this weekend.</p>
                 </div>
                 <div className="w-1/3 h-full relative hidden md:block">
                     {/* Decorative elements representing movies */}
                     <div className="absolute right-0 top-1/2 -translate-y-1/2 w-32 h-48 bg-gray-800 rounded shadow-2xl transform rotate-12 border border-white/20"></div>
                     <div className="absolute right-12 top-1/2 -translate-y-1/2 w-32 h-48 bg-gray-700 rounded shadow-2xl transform -rotate-6 border border-white/20"></div>
                 </div>
             </div>
        </div>

      </div>

      {/* Custom CSS for Text Outline effect used in Top 10 */}
      <style>{`
        .font-outline-2 {
            -webkit-text-stroke: 2px rgba(255,255,255,0.2);
        }
        .text-kada-pink { color: #ff0080; }
        .text-kada-yellow { color: #ffcc00; }
        .perspective-1000 { perspective: 1000px; }
