import React, { useState, useRef, useEffect } from 'react';
import { PlayIcon, PauseIcon, VolumeHighIcon, VolumeMuteIcon, MaximizeIcon, SkipForwardIcon, CloseIcon, ListIcon, PhoneRotateIcon, SpeedIcon, QualityIcon, SubtitleIcon, ExternalLinkIcon, SettingsIcon } from './Icons';
import { Ad, SubtitleTrack } from '../types';

interface NextVideo {
  title: string;
  thumbnailUrl: string;
  subTitle?: string;
  onPlay: () => void;
}

interface RecommendedItem {
    id: string;
    title: string;
    thumbnailUrl: string;
    trailerUrl?: string;
    action: () => void;
}

interface VideoPlayerProps {
  src: string;
  poster?: string;
  title?: string;
  subTitle?: string;
  ads?: Ad[];
  nextVideo?: NextVideo | null;
  recommendedItem?: RecommendedItem | null;
  onEnded?: () => void;
  autoPlay?: boolean;
  startTime?: number; 
  isSeries?: boolean;
  onToggleEpisodes?: () => void;
  onClose?: () => void;
  onProgress?: (currentTime: number, duration: number) => void;
  initialSubtitles?: SubtitleTrack[];
  isLive?: boolean;
}

const PLAYBACK_SPEEDS = [0.5, 0.75, 1, 1.25, 1.5, 2];
const QUALITIES = ['Auto', '4K', '1080p', '720p', '480p'];

const VideoPlayer: React.FC<VideoPlayerProps> = ({ 
  src, poster, title, subTitle, ads = [], nextVideo, recommendedItem, onEnded, autoPlay = false, startTime = 0,
  isSeries, onToggleEpisodes, onClose, onProgress, initialSubtitles = [], isLive = false
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [isHovering, setIsHovering] = useState(false);
  const [playbackRate, setPlaybackRate] = useState(1);

  const [subtitles, setSubtitles] = useState<SubtitleTrack[]>(initialSubtitles);
  const [activeSubtitle, setActiveSubtitle] = useState<string | null>(null);
  const [showSubtitleMenu, setShowSubtitleMenu] = useState(false);

  const [showSpeedMenu, setShowSpeedMenu] = useState(false);
  const [showQualityMenu, setShowQualityMenu] = useState(false);
  const [activeQuality, setActiveQuality] = useState('Auto');

  const [showRecommendation, setShowRecommendation] = useState(false);

  const [adState, setAdState] = useState<'idle' | 'playing' | 'completed'>('idle');
  const [currentAd, setCurrentAd] = useState<Ad | null>(null);
  const [activeBannerAd, setActiveBannerAd] = useState<Ad | null>(null);
  const [adTimeLeft, setAdTimeLeft] = useState(0);
  const [canSkipAd, setCanSkipAd] = useState(false);
  const [playedAds, setPlayedAds] = useState<string[]>([]);
  const [showSkipRecap, setShowSkipRecap] = useState(false);

  useEffect(() => {
    setIsPlaying(false);
    setCurrentTime(0);
    setAdState('idle');
    setCurrentAd(null);
    setActiveBannerAd(null);
    setPlayedAds([]);
    setShowRecommendation(false);
    setSubtitles(initialSubtitles);
    setActiveSubtitle('off');
    setPlaybackRate(1);
    setActiveQuality('Auto');
    setShowSkipRecap(false);

    let seekTimeout: any;
    let playTimeout: any;

    if (videoRef.current) {
      // Ensure we don't carry over playback state confusingly
      videoRef.current.pause();

      seekTimeout = setTimeout(() => {
          if (videoRef.current && startTime > 0 && startTime < (videoRef.current.duration || Infinity) * 0.95) {
            videoRef.current.currentTime = startTime;
            setCurrentTime(startTime);
          }
      }, 100);
    }

    if (autoPlay && videoRef.current) {
      playTimeout = setTimeout(() => {
        if (videoRef.current) {
             const playPromise = videoRef.current.play();
             if (playPromise !== undefined) {
                 playPromise.catch(err => {
                     // Ignore AbortError (happens when element removed or src changed quickly)
                     if (err.name !== 'AbortError') {
                         console.log('Autoplay prevented', err);
                     }
                 });
             }
        }
      }, 500);
    }

    return () => {
        if (seekTimeout) clearTimeout(seekTimeout);
        if (playTimeout) clearTimeout(playTimeout);
    };
  }, [src]);

  const formatTime = (time: number) => {
    if (isNaN(time)) return "00:00";
    const hours = Math.floor(time / 3600);
    const minutes = Math.floor((time % 3600) / 60);
    const seconds = Math.floor(time % 60);

    if (hours > 0) {
        return `${hours}:${minutes < 10 ? '0' + minutes : minutes}:${seconds < 10 ? '0' + seconds : seconds}`;
    }
    return `${minutes}:${seconds < 10 ? '0' + seconds : seconds}`;
  };

  const checkForAds = (time: number) => {
    if (adState === 'playing') return;

    // Preroll
    if (time < 0.5 && !playedAds.includes('preroll')) {
      const preroll = ads.find(a => a.type === 'preroll');
      if (preroll) {
        playAd(preroll, 'preroll');
        return;
      }
    }

    // Midroll
    const midrolls = ads.filter(a => a.type === 'midroll' && !playedAds.includes(a.id));
    for (const ad of midrolls) {
      if (ad.startTime && Math.abs(time - ad.startTime) < 1) {
        playAd(ad, ad.id);
        return;
      }
    }

    // Banner Ads Logic (Mocked frequency)
    if (!activeBannerAd && time > 60 && time % 300 < 1 && !playedAds.includes('banner-' + Math.floor(time))) {
        const banner = ads.find(a => a.type === 'banner');
        if (banner) {
            setActiveBannerAd(banner);
            setPlayedAds(prev => [...prev, 'banner-' + Math.floor(time)]);
            // Auto hide after 15s
            setTimeout(() => setActiveBannerAd(null), 15000);
        }
    }

    // Skip Recap Logic
    if (isSeries && time > 0 && time < 45 && !showSkipRecap) {
        setShowSkipRecap(true);
    } else if ((time >= 45 || adState === 'playing') && showSkipRecap) {
        setShowSkipRecap(false);
    }
  };

  const playAd = (ad: Ad, adIdToMark: string) => {
    if (!videoRef.current) return;
    videoRef.current.pause();
    setIsPlaying(false);
    setCurrentAd(ad);
    setAdState('playing');
    setAdTimeLeft(ad.duration);
    setCanSkipAd(false);
    setPlayedAds(prev => [...prev, adIdToMark]);
    if (ad.skipAfter && ad.skipAfter > 0) {
       setTimeout(() => setCanSkipAd(true), ad.skipAfter * 1000);
    }
  };

  const handleAdTick = () => {
    setAdTimeLeft(prev => {
      if (prev <= 1) {
        finishAd();
        return 0;
      }
      return prev - 1;
    });
  };

  useEffect(() => {
    let interval: any;
    if (adState === 'playing' && currentAd) {
      interval = setInterval(handleAdTick, 1000);
    }
    return () => clearInterval(interval);
  }, [adState, currentAd]);

  const finishAd = () => {
    setAdState('idle');
    setCurrentAd(null);
    if (videoRef.current) {
      const p = videoRef.current.play();
      if (p !== undefined) {
          p.catch(e => { if (e.name !== 'AbortError') console.error("Resume error", e) });
      }
      setIsPlaying(true);
    }
  };

  const skipRecap = () => {
      if (videoRef.current) {
          videoRef.current.currentTime = 45; // Jump to 45s
          setShowSkipRecap(false);
      }
  };

  const togglePlay = () => {
    if (adState === 'playing') return;
    if (showRecommendation) return; 

    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      const p = videoRef.current.play();
      if (p !== undefined) {
          p.catch(e => { if (e.name !== 'AbortError') console.error("Play error", e); });
      }
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const handleTimeUpdate = () => {
    if (!videoRef.current) return;
    const curr = videoRef.current.currentTime;
    const dur = videoRef.current.duration;
    setCurrentTime(curr);
    checkForAds(curr);

    if (onProgress && dur > 0) {
        onProgress(curr, dur);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const time = Number(e.target.value);
    videoRef.current.currentTime = time;
    setCurrentTime(time);
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    videoRef.current.muted = !isMuted;
    setIsMuted(!isMuted);
  };

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const vol = Number(e.target.value);
    videoRef.current.volume = vol;
    setVolume(vol);
    setIsMuted(vol === 0);
  };

  const changeSpeed = (speed: number) => {
    if (videoRef.current) {
        videoRef.current.playbackRate = speed;
        setPlaybackRate(speed);
        setShowSpeedMenu(false);
    }
  };

  const changeQuality = (q: string) => {
      setActiveQuality(q);
      setShowQualityMenu(false);
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen();
    } else {
      document.exitFullscreen();
    }
  };

  const handleMainVideoEnded = () => {
    setIsPlaying(false);
    const postroll = ads.find(a => a.type === 'postroll' && !playedAds.includes('postroll'));
    if (postroll) {
      playAd(postroll, 'postroll');
    } else {
      if (nextVideo) {
        nextVideo.onPlay();
      } else if (recommendedItem) {
        setShowRecommendation(true);
      } else if (onEnded) {
        onEnded();
      }
    }
  };

  const changeSubtitle = (trackId: string) => {
      setActiveSubtitle(trackId);
      setShowSubtitleMenu(false);

      if (videoRef.current) {
          const tracks = videoRef.current.textTracks;
          for (let i = 0; i < tracks.length; i++) {
             const trackData = subtitles.find(s => s.id === trackId);

             if (trackId === 'off') {
                 tracks[i].mode = 'hidden';
             } else if (trackData && (tracks[i].label === trackData.label)) {
                 tracks[i].mode = 'showing';
             } else {
                 tracks[i].mode = 'hidden';
             }
          }
      }
  };

  const closeAllMenus = () => {
      setShowSpeedMenu(false);
      setShowQualityMenu(false);
      setShowSubtitleMenu(false);
  };

  useEffect(() => {
    let timeout: any;
    if (isHovering) {
      if (timeout) clearTimeout(timeout);
      timeout = setTimeout(() => {
        if (isPlaying && !showSpeedMenu && !showQualityMenu && !showSubtitleMenu) setIsHovering(false);
      }, 4000);
    }
    return () => clearTimeout(timeout);
  }, [isHovering, isPlaying, showSpeedMenu, showQualityMenu, showSubtitleMenu]);

  const showControls = !showRecommendation && adState !== 'playing' && (isHovering || !isPlaying || showSpeedMenu || showQualityMenu || showSubtitleMenu);

  return (
    <div 
      ref={containerRef}
      className="relative w-full h-full bg-black group overflow-hidden select-none font-sans"
      onMouseEnter={() => setIsHovering(true)}
      onMouseLeave={() => setIsHovering(false)}
      onMouseMove={() => setIsHovering(true)}
      onClick={closeAllMenus}
    >

      {/* Mobile Portrait Warning */}
      <div className="absolute inset-0 z-[60] bg-black flex-col items-center justify-center text-center p-10 hidden portrait:flex lg:portrait:hidden">
        <PhoneRotateIcon className="w-16 h-16 text-kada-pink mb-4 animate-bounce" />
        <h3 className="text-2xl font-bold text-white mb-2">Please Rotate Device</h3>
        <p className="text-gray-400">For the best cinematic experience, please switch to landscape mode.</p>
      </div>

      <video
        ref={videoRef}
        src={src}
        poster={poster}
        className="w-full h-full object-contain"
        onClick={(e) => { e.stopPropagation(); togglePlay(); }}
        onTimeUpdate={handleTimeUpdate}
        onLoadedMetadata={() => {
            if (videoRef.current) {
                setDuration(videoRef.current.duration || 0);
            }
        }}
        onEnded={handleMainVideoEnded}
        onPlay={() => setIsPlaying(true)}
        onPause={() => setIsPlaying(false)}
        crossOrigin="anonymous"
      >
          {subtitles.map((track, index) => (
              <track 
                 key={track.id}
                 kind="subtitles"
                 src={track.src}
                 srcLang={track.language}
                 label={track.label}
                 default={activeSubtitle === track.id}
              />
          ))}
      </video>

      {/* Top Overlay - Glass Gradient */}
      {showControls && (title || subTitle) && (
        <div className="absolute top-0 left-0 right-0 p-8 bg-gradient-to-b from-black/90 to-transparent z-40 pointer-events-none transition-opacity duration-500">
            <h2 className="text-white font-bold text-3xl drop-shadow-lg tracking-tight">{title}</h2>
            {subTitle && <p className="text-gray-200 text-base font-medium drop-shadow-md mt-1">{subTitle}</p>}
        </div>
      )}

      {/* Close Button - Floating Glass */}
      {showControls && onClose && (
        <button 
          onClick={onClose}
          className="absolute top-8 right-8 z-50 w-12 h-12 rounded-full glass-panel flex items-center justify-center text-white transition-all hover:bg-white/20 hover:scale-110 pointer-events-auto shadow-lg group/close"
          title="Exit Player"
        >
          <CloseIcon className="w-6 h-6 group-hover/close:rotate-90 transition-transform duration-300" />
        </button>
      )}

      {/* BANNER AD OVERLAY */}
      {activeBannerAd && (
          <div className="absolute bottom-32 left-1/2 -translate-x-1/2 z-[45] animate-fade-in-up">
              <div className="bg-black/80 backdrop-blur-md border border-white/20 p-4 rounded-xl shadow-2xl relative max-w-lg flex items-center gap-4">
                  <button onClick={(e) => { e.stopPropagation(); setActiveBannerAd(null); }} className="absolute -top-3 -right-3 bg-white text-black rounded-full p-1 shadow-lg hover:bg-gray-200">
                      <CloseIcon className="w-4 h-4" />
                  </button>
                  {activeBannerAd.imageUrl ? (
                      <img src={activeBannerAd.imageUrl} className="w-24 h-16 object-cover rounded" />
                  ) : (
                      <div className="w-24 h-16 bg-gray-700 rounded flex items-center justify-center text-xs text-gray-400">Ad Image</div>
                  )}
                  <div className="flex-1">
                      <h4 className="font-bold text-white text-sm">{activeBannerAd.advertiserName || 'Sponsored'}</h4>
                      <p className="text-xs text-gray-300 mb-2">Check out our latest offers today.</p>
                      {activeBannerAd.linkUrl && (
                          <a href={activeBannerAd.linkUrl} target="_blank" className="text-xs bg-kada-pink text-white px-3 py-1 rounded font-bold hover:bg-pink-600 inline-block">Learn More</a>
                      )}
                  </div>
              </div>
          </div>
      )}

      {/* SKIP RECAP BUTTON */}
      {showSkipRecap && !isLive && (
          <div className="absolute bottom-32 right-12 z-[45] animate-fade-in">
              <button 
                onClick={skipRecap}
                className="bg-white/10 backdrop-blur-md border border-white/30 text-white px-6 py-2 rounded-full font-bold hover:bg-white hover:text-black transition-all flex items-center gap-2 shadow-lg"
              >
                  Skip Recap <SkipForwardIcon className="w-4 h-4" />
              </button>
          </div>
      )}

      {/* AD OVERLAY */}
      {adState === 'playing' && currentAd && (
        <div className="absolute inset-0 z-50 bg-black flex flex-col items-center justify-center">
           <video 
             src={currentAd.videoUrl}
             autoPlay 
             className="absolute inset-0 w-full h-full object-contain"
           />

           <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-start pointer-events-auto">
                <div className="flex gap-2">
                    <span className="glass-panel text-white text-xs font-bold px-3 py-1.5 rounded-full border border-kada-yellow/50 text-kada-yellow uppercase tracking-wider">Ad</span>
                    {currentAd.advertiserName && (
                        <span className="glass-panel text-white text-xs font-bold px-3 py-1.5 rounded-full">
                            {currentAd.advertiserName}
                        </span>
                    )}
                </div>

                <div className="w-12 h-12 rounded-full glass-panel flex items-center justify-center border border-white/20 relative">
                    <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 36 36">
                        <path className="text-white/10" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="3" />
                        <path className="text-kada-yellow transition-all duration-1000 linear" strokeDasharray={`${(adTimeLeft / currentAd.duration) * 100}, 100`} d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="3" />
                    </svg>
                    <span className="text-sm font-bold text-white">{adTimeLeft}</span>
                </div>
           </div>

           <div className="absolute bottom-10 right-8 left-8 flex justify-between items-end pointer-events-auto z-50">
               <div>
                  {currentAd.linkUrl && (
                      <a href={currentAd.linkUrl} target="_blank" rel="noreferrer" className="flex items-center gap-2 glass-panel hover:bg-white/20 text-white px-6 py-3 rounded-full font-bold transition-all border border-white/20 group">
                          Visit Advertiser <ExternalLinkIcon className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                      </a>
                  )}
               </div>

              <div className="flex flex-col items-end space-y-4">
                  {canSkipAd ? (
                    <button onClick={finishAd} className="flex items-center gap-2 bg-white text-black px-8 py-3 rounded-full font-bold hover:scale-105 transition-all shadow-[0_0_20px_rgba(255,255,255,0.4)]">
                      Skip Ad <SkipForwardIcon className="w-5 h-5" />
                    </button>
                  ) : (
                    <div className="glass-panel px-6 py-3 rounded-full text-gray-300 text-sm font-medium border border-white/10">
                       Skip in <span className="text-white font-bold ml-1">{currentAd.skipAfter ? Math.max(0, currentAd.skipAfter - (currentAd.duration - adTimeLeft)) : adTimeLeft}s</span>
                    </div>
                  )}
              </div>
           </div>
        </div>
      )}

      {/* RECOMMENDATION OVERLAY */}
      {showRecommendation && recommendedItem && (
        <div className="absolute inset-0 z-50 bg-black flex flex-col items-center justify-center overflow-hidden animate-fade-in">
             {recommendedItem.trailerUrl && (
                 <div className="absolute inset-0 opacity-40">
                    <video src={recommendedItem.trailerUrl} autoPlay muted loop className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black via-black/60 to-black/80"></div>
                 </div>
             )}

             <div className="relative z-10 text-center p-8 max-w-4xl w-full">
                 <div className="text-kada-pink text-sm uppercase tracking-[0.3em] font-bold mb-6">Up Next</div>
                 <h2 className="text-5xl md:text-7xl font-black text-white mb-8 tracking-tight">{recommendedItem.title}</h2>

                 <div className="flex flex-col md:flex-row items-center justify-center gap-8 md:gap-12">
                     <div className="w-full max-w-sm aspect-video rounded-2xl overflow-hidden shadow-[0_0_40px_rgba(0,0,0,0.5)] relative border border-white/10 group cursor-pointer" onClick={() => recommendedItem.action()}>
                         <img src={recommendedItem.thumbnailUrl} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                         <div className="absolute inset-0 flex items-center justify-center">
                             <div className="w-16 h-16 rounded-full bg-white/20 backdrop-blur-md flex items-center justify-center border border-white/50 group-hover:scale-110 transition-transform">
                                 <PlayIcon className="w-8 h-8 text-white fill-white translate-x-0.5" />
                             </div>
                         </div>
                     </div>

                     <div className="flex flex-col gap-4 min-w-[200px]">
                         <button 
                            onClick={() => recommendedItem.action()}
                            className="px-8 py-4 bg-white text-black font-bold text-lg rounded-full hover:bg-gray-200 transition-all flex items-center justify-center gap-2 hover:scale-105 shadow-xl"
                         >
                             Play Now
                         </button>
                         <button 
                            onClick={onClose} 
                            className="px-8 py-4 glass-panel text-white font-bold text-lg rounded-full hover:bg-white/10 transition-all border border-white/20"
                         >
                             Cancel
                         </button>
                     </div>
                 </div>
             </div>
        </div>
      )}

      {/* CONTROLS BAR - Floating Glass Pill */}
      {showControls && (
        <div className="absolute bottom-8 left-4 right-4 md:left-12 md:right-12 z-40 animate-fade-in-up">
          <div className="bg-black/60 backdrop-blur-xl border border-white/10 rounded-2xl px-6 py-4 shadow-2xl relative">

              {/* Progress Bar - Floating above (Hidden for Live) */}
              {!isLive && (
                  <div className="absolute -top-3 left-4 right-4 group/progress h-1.5 cursor-pointer">
                     <div className="absolute inset-0 bg-white/20 rounded-full overflow-hidden backdrop-blur-sm">
                         <div 
                           className="h-full bg-gradient-to-r from-kada-pink to-kada-yellow rounded-full relative"
                           style={{ width: `${(currentTime / duration) * 100}%` }}
                         >
                            <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full shadow-[0_0_10px_rgba(255,255,255,0.8)] opacity-0 group-hover/progress:opacity-100 scale-0 group-hover/progress:scale-150 transition-all"></div>
                         </div>
                     </div>
                     <input 
                       type="range" 
                       min="0" 
                       max={duration || 100} 
                       value={currentTime} 
                       onChange={handleSeek}
                       onClick={(e) => e.stopPropagation()}
                       className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                     />
                  </div>
              )}

              <div className="flex items-center justify-between pt-2">
                {/* Left Controls */}
                <div className="flex items-center gap-6">
                   <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="text-white hover:text-kada-pink transition-colors hover:scale-110 transform">
                     {isPlaying ? <PauseIcon className="w-8 h-8" /> : <PlayIcon className="w-8 h-8 fill-current" />}
                   </button>

                   {!isLive && (
                       <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime -= 10; }} className="text-gray-300 hover:text-white transition-colors text-xs font-bold -ml-2">
                           -10s
                       </button>
                   )}

                   <div className="flex items-center gap-3 group/volume" onClick={(e) => e.stopPropagation()}>
                     <button onClick={toggleMute} className="text-gray-300 hover:text-white transition-colors">
                       {isMuted || volume === 0 ? <VolumeMuteIcon className="w-6 h-6" /> : <VolumeHighIcon className="w-6 h-6" />}
                     </button>
                     <div className="w-0 group-hover/volume:w-24 transition-all duration-300 overflow-hidden flex items-center">
                        <input 
                          type="range" 
                          min="0" 
                          max="1" 
                          step="0.1" 
                          value={isMuted ? 0 : volume}
                          onChange={handleVolumeChange}
                          className="w-20 h-1 bg-white/30 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:rounded-full hover:[&::-webkit-slider-thumb]:scale-110"
                        />
                     </div>
                   </div>

                   {!isLive ? (
                       <div className="text-xs font-bold text-gray-400 tracking-wider">
                         <span className="text-white">{formatTime(currentTime)}</span> / {formatTime(duration)}
                       </div>
                   ) : (
                       <div className="flex items-center gap-2">
                           <div className="w-2 h-2 rounded-full bg-red-600 animate-pulse"></div>
                           <span className="text-xs font-bold text-red-500 uppercase tracking-widest">Live</span>
                       </div>
                   )}
                </div>

                {/* Right Controls */}
                <div className="flex items-center gap-4 relative">

                   {/* Subtitles */}
                   <div className="relative">
                      <button onClick={(e) => { e.stopPropagation(); setShowSubtitleMenu(!showSubtitleMenu); setShowSpeedMenu(false); setShowQualityMenu(false); }} className={`hover:text-white transition-colors hover:scale-110 ${activeSubtitle && activeSubtitle !== 'off' ? 'text-kada-pink' : 'text-gray-300'}`}>
                         <SubtitleIcon className="w-5 h-5" />
                      </button>
                      {showSubtitleMenu && (
                          <div className="absolute bottom-full mb-6 left-1/2 -translate-x-1/2 bg-black/90 backdrop-blur-xl border border-white/10 rounded-xl py-2 min-w-[180px] shadow-2xl overflow-hidden z-50 animate-fade-in-up origin-bottom">
                              <div className="px-4 py-2 text-[10px] font-bold text-gray-500 uppercase tracking-wider border-b border-white/10 mb-1">Subtitles</div>
                              <button onClick={(e) => { e.stopPropagation(); changeSubtitle('off'); }} className={`block w-full text-left px-4 py-2 text-sm hover:bg-white/10 transition-colors ${activeSubtitle === 'off' ? 'text-kada-pink font-bold' : 'text-gray-300'}`}>Off</button>
                              {subtitles.map(track => (
                                  <button key={track.id} onClick={(e) => { e.stopPropagation(); changeSubtitle(track.id); }} className={`block w-full text-left px-4 py-2 text-sm hover:bg-white/10 transition-colors ${activeSubtitle === track.id ? 'text-kada-pink font-bold' : 'text-gray-300'}`}>{track.label}</button>
                              ))}
                          </div>
                      )}
                   </div>

                   {/* Settings (Quality & Speed) */}
                   {!isLive && (
                       <div className="relative group/settings">
                            <button className="text-gray-300 hover:text-white transition-colors hover:scale-110 hover:rotate-45 duration-300">
                                <SettingsIcon className="w-5 h-5" />
                            </button>
                            <div className="absolute bottom-full mb-6 right-0 bg-black/90 backdrop-blur-xl border border-white/10 rounded-xl p-2 min-w-[200px] shadow-2xl overflow-hidden z-50 hidden group-hover/settings:block animate-fade-in-up origin-bottom-right">
                                {/* Quality Section */}
                                <div className="px-3 py-2">
                                    <div className="text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Quality</div>
                                    <div className="flex flex-wrap gap-2">
                                        {QUALITIES.map(q => (
                                            <button key={q} onClick={() => changeQuality(q)} className={`px-2 py-1 rounded text-xs font-bold transition-colors ${activeQuality === q ? 'bg-kada-pink text-white' : 'bg-white/10 text-gray-400 hover:text-white'}`}>{q}</button>
                                        ))}
                                    </div>
                                </div>
                                <div className="h-px bg-white/10 my-1"></div>
                                {/* Speed Section */}
                                <div className="px-3 py-2">
                                    <div className="text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Speed</div>
                                    <div className="flex flex-wrap gap-2">
                                        {PLAYBACK_SPEEDS.map(s => (
                                            <button key={s} onClick={() => changeSpeed(s)} className={`px-2 py-1 rounded text-xs font-bold transition-colors ${playbackRate === s ? 'bg-kada-pink text-white' : 'bg-white/10 text-gray-400 hover:text-white'}`}>{s}x</button>
                                        ))}
                                    </div>
                                </div>
                            </div>
                       </div>
                   )}

                   {/* Next Episode Button */}
                   {nextVideo && (
                     <button 
                        onClick={(e) => { e.stopPropagation(); nextVideo.onPlay(); }} 
                        className="flex items-center gap-2 bg-white/10 hover:bg-white/20 text-white rounded-full px-4 py-1.5 transition-colors border border-white/10"
                        title="Next Episode"
                     >
                       <span className="text-xs font-bold">Next Ep</span>
                       <SkipForwardIcon className="w-4 h-4" />
                     </button>
                   )}

                   {(isSeries || isLive) && onToggleEpisodes && (
                     <button onClick={(e) => { e.stopPropagation(); onToggleEpisodes(); }} className="text-gray-300 hover:text-white transition-colors hover:scale-110">
                       <ListIcon className="w-5 h-5" />
                     </button>
                   )}

                   <button onClick={(e) => { e.stopPropagation(); toggleFullscreen(); }} className="text-gray-300 hover:text-white transition-colors hover:scale-110 ml-2">
                     <MaximizeIcon className="w-5 h-5" />
                   </button>
                </div>
              </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default VideoPlayer;

import React, { useEffect, useState, useRef, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import MediaCard from '../components/MediaCard';
import { PlayIcon, InfoIcon, TrendingUpIcon, StarIcon, FilmIcon, TvIcon, VolumeMuteIcon, VolumeHighIcon, ClockIcon, PlusIcon, SparklesIcon, CalendarIcon } from '../components/Icons';
import { store } from '../store';
import { MediaItem, UserProfile, AppSettings, Channel } from '../types';

const Home: React.FC = () => {
  const navigate = useNavigate();
  const [library, setLibrary] = useState<MediaItem[]>([]);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [settings, setSettings] = useState<AppSettings>(store.getSettings());
  const [channels, setChannels] = useState<Channel[]>([]);

  // Hero Slider State
  const [featuredItems, setFeaturedItems] = useState<MediaItem[]>([]);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [showVideo, setShowVideo] = useState(false);
  const [isMuted, setIsMuted] = useState(true);
  const slideInterval = useRef<any>(null);
  const videoRef = useRef<HTMLVideoElement>(null); // Ref for hero video

  useEffect(() => {
    setLibrary(store.getLibrary());
    setProfile(store.getCurrentProfile());
    setSettings(store.getSettings());
    setChannels(store.getChannels());

    const unsubLibrary = store.subscribe('library', () => setLibrary(store.getLibrary()));
    const unsubProfile = store.subscribe('profile', () => setProfile(store.getCurrentProfile()));
    const unsubSettings = store.subscribe('settings', () => setSettings(store.getSettings()));

    return () => {
      unsubLibrary();
      unsubProfile();
      unsubSettings();
    };
  }, []);

  const simulatedCountry = settings.simulatedCountry || 'US';

  const safeLibrary = useMemo(() => {
    if (!profile) return [];
    return library.filter(item => {
        const kidsCheck = profile.isKids ? item.isKidsSafe : true;
        let geoCheck = true;
        if (item.allowedCountries && item.allowedCountries.length > 0) {
            geoCheck = item.allowedCountries.includes(simulatedCountry);
        }
        return kidsCheck && geoCheck;
    });
  }, [library, profile, simulatedCountry]);

  useEffect(() => {
      if (safeLibrary.length > 0) {
          const featured = safeLibrary.filter(item => item.trending && !item.isComingSoon).slice(0, 5);
          setFeaturedItems(featured.length > 0 ? featured : safeLibrary.slice(0, 5));
      }
  }, [safeLibrary]);

  useEffect(() => {
      if (featuredItems.length <= 1) return;
      const nextSlide = () => {
          setShowVideo(false);
          setCurrentSlide(prev => (prev + 1) % featuredItems.length);
      };
      slideInterval.current = setInterval(nextSlide, 15000);
      return () => { if (slideInterval.current) clearInterval(slideInterval.current); };
  }, [featuredItems]);

  useEffect(() => {
      const timer = setTimeout(() => { setShowVideo(true); }, 3000);
      return () => clearTimeout(timer);
  }, [currentSlide]);

  // Handle Video Playback explicitly to avoid "interrupted" errors
  useEffect(() => {
      if (showVideo && videoRef.current) {
          const playPromise = videoRef.current.play();
          if (playPromise !== undefined) {
              playPromise.catch(error => {
                  // Ignore abort errors (happens when slide changes quickly)
                  if (error.name !== 'AbortError') {
                      // console.log("Hero video play error", error);
                  }
              });
          }
      }
  }, [showVideo, currentSlide]);

  const activeSlide = featuredItems[currentSlide];

  // Specific Categorized Lists
  const trending = safeLibrary.filter(item => item.trending && !item.isComingSoon).slice(0, 10);
  const topMovies = safeLibrary.filter(item => item.type === 'movie' && !item.isComingSoon).sort((a, b) => (b.analytics?.views || 0) - (a.analytics?.views || 0)).slice(0, 10);
  const freshArrivals = safeLibrary.filter(item => !item.isComingSoon && item.year >= 2023).slice(0, 8);
  const actionMovies = safeLibrary.filter(item => !item.isComingSoon && item.genre === 'Action');
  const comedies = safeLibrary.filter(item => !item.isComingSoon && item.genre === 'Comedy');
  const sciFiSeries = safeLibrary.filter(item => !item.isComingSoon && (item.genre === 'Science' || item.genre === 'Physics' || item.tags.includes('Sci-Fi')));
  const bingeWorthy = safeLibrary.filter(item => item.type === 'series' && !item.isComingSoon);

  // Spotlight Logic
  const spotlightMovie = useMemo(() => {
      const candidates = safeLibrary.filter(m => m.type === 'movie' && !m.isComingSoon && m.id !== activeSlide?.id);
      return candidates.length > 0 ? candidates[Math.floor(Math.random() * candidates.length)] : null;
  }, [safeLibrary, activeSlide]);

  const continueWatching = useMemo(() => {
      if (!profile) return [];

      const seenMediaIds = new Set<string>();
      const result: { item: MediaItem, history: any }[] = [];

      const sortedHistory = [...profile.watchHistory].sort((a, b) => b.lastWatchedAt - a.lastWatchedAt);

      for (const h of sortedHistory) {
          if (h.progress >= 0.95) continue; 
          if (seenMediaIds.has(h.mediaId)) continue; 

          const item = safeLibrary.find(m => m.id === h.mediaId);
          if (item) {
              seenMediaIds.add(h.mediaId);
              result.push({ item, history: h });
          }
          if (result.length >= 4) break;
      }
      return result;
  }, [profile, safeLibrary]);

  if (!profile) return null; 
  if (featuredItems.length === 0) return (
      <div className="h-screen flex items-center justify-center text-white bg-black">
          <p>No content available.</p>
      </div>
  );

  return (
    <div className="pb-20">

      {/* Glass Hero Section */}
      <div className="relative w-full h-[85vh] overflow-hidden flex items-center justify-center">
        {/* Background Video/Image */}
        <div className="absolute inset-0 z-0">
             {showVideo && activeSlide.trailerUrl ? (
                 <video 
                    ref={videoRef}
                    src={activeSlide.trailerUrl}
                    className="w-full h-full object-cover scale-105"
                    // autoPlay removed to handle manually
                    muted={isMuted}
                    loop
                    playsInline
                 />
             ) : (
                 <img 
                    src={activeSlide.backdropUrl || activeSlide.thumbnailUrl} 
                    alt={activeSlide.title}
                    className="w-full h-full object-cover animate-pulse-slow"
                 />
             )}
             <div className="absolute inset-0 bg-black/40"></div>
             <div className="absolute inset-0 bg-gradient-to-t from-kada-dark via-transparent to-transparent"></div>
             <div className="absolute inset-0 bg-gradient-to-r from-kada-dark/90 via-transparent to-kada-dark/90"></div>
        </div>

        {/* Floating Glass Content Card */}
        <div className="relative z-10 max-w-6xl w-full px-6 flex flex-col md:flex-row items-center gap-12 mt-16">
            <div className="flex-1 space-y-6 text-center md:text-left">
                 <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full border border-white/20 bg-black/30 backdrop-blur-md">
                    <span className="w-2 h-2 rounded-full bg-kada-pink animate-pulse"></span>
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Featured Premiere</span>
                 </div>
                 <h1 className="text-4xl md:text-6xl lg:text-7xl font-black text-transparent bg-clip-text bg-gradient-to-br from-white via-white to-gray-400 drop-shadow-2xl leading-none">
                     {activeSlide.title}
                 </h1>
                 <div className="flex flex-wrap items-center justify-center md:justify-start gap-4 text-sm font-semibold text-gray-300">
                     <span className="text-kada-yellow">{activeSlide.year}</span>
                     <span className="w-1 h-1 rounded-full bg-gray-500"></span>
                     <span>{activeSlide.genre}</span>
                     <span className="w-1 h-1 rounded-full bg-gray-500"></span>
                     <span className="border border-gray-500 px-2 rounded">{activeSlide.rating}</span>
                 </div>
                 <p className="text-base md:text-lg text-gray-200 line-clamp-3 md:line-clamp-none max-w-xl mx-auto md:mx-0 drop-shadow-lg leading-relaxed">
                     {activeSlide.description}
                 </p>
                 <div className="flex items-center justify-center md:justify-start gap-4 pt-4">
                     <Link to={`/watch/${activeSlide.id}`} className="group relative px-8 py-3 bg-white text-black rounded-full font-bold text-lg overflow-hidden shadow-[0_0_20px_rgba(255,255,255,0.3)] transition-all hover:scale-105">
                         <div className="absolute inset-0 bg-gradient-to-r from-kada-pink to-kada-yellow opacity-0 group-hover:opacity-100 transition-opacity"></div>
                         <div className="relative flex items-center gap-2 group-hover:text-white transition-colors">
                            <PlayIcon className="w-6 h-6 fill-current" /> <span>Watch Now</span>
                         </div>
                     </Link>
                     <Link to={`/title/${activeSlide.id}`} className="px-8 py-3 glass-panel rounded-full font-bold text-lg hover:bg-white/10 transition-all flex items-center gap-2 border border-white/20">
                         <InfoIcon className="w-6 h-6" /> Details
                     </Link>
                 </div>
            </div>
            <div className="hidden md:block w-72 lg:w-80 aspect-[2/3] relative group perspective-1000">
                <div className="absolute inset-0 bg-gradient-to-tr from-kada-pink to-kada-yellow rounded-2xl blur-lg opacity-40 group-hover:opacity-60 transition-opacity"></div>
                <div className="relative h-full w-full rounded-2xl overflow-hidden border border-white/20 shadow-2xl transform rotate-y-12 group-hover:rotate-y-0 transition-transform duration-700">
                    <img src={activeSlide.posterUrl || activeSlide.thumbnailUrl} className="w-full h-full object-cover" />
                </div>
                {showVideo && (
                    <button onClick={() => setIsMuted(!isMuted)} className="absolute bottom-4 right-4 w-10 h-10 rounded-full glass-panel flex items-center justify-center hover:bg-white/20 transition-colors z-20">
                        {isMuted ? <VolumeMuteIcon className="w-5 h-5 text-white" /> : <VolumeHighIcon className="w-5 h-5 text-white" />}
                    </button>
                )}
            </div>
        </div>
        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex gap-2 z-20">
            {featuredItems.map((_, idx) => (
                <button key={idx} onClick={() => { setCurrentSlide(idx); setShowVideo(false); }} className={`h-1.5 rounded-full transition-all duration-300 ${currentSlide === idx ? 'w-8 bg-white shadow-[0_0_10px_rgba(255,255,255,0.8)]' : 'w-2 bg-white/30 hover:bg-white/60'}`} />
            ))}
        </div>
      </div>

      {/* Content Section */}
      <div className="container mx-auto px-6 relative z-10 -mt-10 space-y-16">

        {/* Live TV Row */}
        {channels.length > 0 && (
             <section>
                 <div className="flex items-center justify-between mb-6">
                     <div className="flex items-center gap-3">
                         <div className="p-2 rounded-full bg-red-600/20 text-red-500 animate-pulse"><div className="w-3 h-3 bg-red-500 rounded-full"></div></div>
                         <h2 className="text-2xl font-bold text-white tracking-tight">Live TV</h2>
                     </div>
                     <Link to="/live" className="text-sm font-bold text-kada-pink hover:text-white transition-colors">View All Channels</Link>
                 </div>
                 <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-4">
                     {channels.slice(0, 4).map(channel => (
                         <Link key={channel.id} to={`/watch/${channel.id}`} className="group relative aspect-video rounded-xl overflow-hidden border border-white/10 hover:border-kada-pink/50 transition-all bg-zinc-900">
                             <img src={channel.logoUrl} className="absolute top-4 left-4 w-12 h-12 rounded object-contain bg-black/50 p-1 z-10" />
                             <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent z-0"></div>
                             <div className="w-full h-full bg-zinc-800 group-hover:scale-105 transition-transform duration-700"></div>
                             <div className="absolute bottom-0 left-0 w-full p-4 z-10">
                                 <h3 className="font-bold text-white text-lg">{channel.name}</h3>
                                 <p className="text-xs text-gray-400 truncate">{channel.currentProgram}</p>
                             </div>
                             <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all z-20">
                                 <div className="w-12 h-12 rounded-full bg-white text-black flex items-center justify-center shadow-lg transform scale-50 group-hover:scale-100 transition-transform">
                                     <PlayIcon className="w-5 h-5 ml-0.5" />
                                 </div>
                             </div>
                         </Link>
                     ))}
                 </div>
             </section>
        )}

        {/* Continue Watching */}
        {continueWatching.length > 0 && (
           <section>
             <div className="flex items-center gap-3 mb-6">
                <div className="p-2 rounded-full bg-white/10 text-kada-pink"><ClockIcon className="w-5 h-5" /></div>
                <h2 className="text-2xl font-bold text-white tracking-tight">Continue Watching</h2>
             </div>
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                {continueWatching.map(({ item, history }) => (
                   <div key={`${item!.id}-${history.episodeId || ''}`} className="relative group">
                      <MediaCard item={item!} progress={history.progress} />
                   </div>
                ))}
             </div>
           </section>
        )}

        {/* Fresh Arrivals - Landscape Scroll */}
        {freshArrivals.length > 0 && (
            <section>
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 rounded-full bg-white/10 text-green-400"><SparklesIcon className="w-5 h-5" /></div>
                    <h2 className="text-2xl font-bold text-white tracking-tight">Fresh Arrivals</h2>
                </div>
                <div className="flex overflow-x-auto gap-6 pb-4 no-scrollbar">
                    {freshArrivals.map(item => (
                        <div key={item.id} className="min-w-[280px] md:min-w-[320px] aspect-video">
                            <MediaCard item={item} />
                        </div>
                    ))}
                </div>
            </section>
        )}

        {/* PREMIUM PROMO BANNER */}
        <div className="relative w-full aspect-[21/9] md:aspect-[4/1] rounded-2xl overflow-hidden border border-white/10 group cursor-pointer my-10">
            <div className="absolute inset-0 bg-gradient-to-r from-purple-900 to-blue-900">
               <div className="absolute inset-0 opacity-20" style={{backgroundImage: 'radial-gradient(circle at 2px 2px, rgba(255,255,255,0.15) 1px, transparent 0)', backgroundSize: '24px 24px'}}></div>
            </div>
            <div className="absolute inset-0 flex flex-col md:flex-row items-center justify-between p-8 md:p-16 relative z-10">
               <div className="space-y-4 text-center md:text-left">
                   <span className="inline-block px-4 py-1 rounded-full bg-white/10 text-xs font-bold uppercase tracking-widest text-blue-300 border border-blue-500/30">Limited Time</span>
                   <h2 className="text-3xl md:text-5xl font-black text-white leading-tight">Unlock the Universe. <br /><span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-purple-400">Go Premium Today.</span></h2>
                   <p className="text-gray-300 max-w-lg">Get access to exclusive 4K content, download for offline viewing, and enjoy an ad-free experience.</p>
               </div>
               <button className="mt-6 md:mt-0 px-8 py-4 bg-white text-black font-bold rounded-full hover:scale-105 transition-transform shadow-[0_0_30px_rgba(255,255,255,0.3)]">
                   Upgrade Now
               </button>
            </div>
            <div className="absolute -bottom-20 -right-20 w-96 h-96 bg-purple-500 rounded-full blur-[120px] opacity-30"></div>
            <div className="absolute -top-20 -left-20 w-96 h-96 bg-blue-500 rounded-full blur-[120px] opacity-30"></div>
        </div>

        {/* Top 10 Stylized Row */}
        {topMovies.length > 0 && (
            <section>
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 rounded-full bg-white/10 text-kada-yellow"><StarIcon className="w-5 h-5" /></div>
                    <h2 className="text-2xl font-bold text-white tracking-tight">Top 10 Movies</h2>
                </div>
                <div className="flex overflow-x-auto gap-8 pb-8 no-scrollbar pl-4 items-center">
                    {topMovies.map((item, index) => (
                        <div key={item.id} className="flex-shrink-0 relative group flex items-end">
                            <span className="text-[120px] font-black text-transparent bg-clip-text bg-gradient-to-b from-gray-700 to-transparent leading-none -mr-10 z-0 scale-y-110 translate-y-4 font-outline-2">{index + 1}</span>
                            <div className="w-40 z-10 transition-transform duration-300 group-hover:-translate-y-4">
                               <MediaCard item={item} variant="portrait" />
                            </div>
                        </div>
                    ))}
                </div>
            </section>
        )}

        {/* SPOTLIGHT MOVIE BANNER */}
        {spotlightMovie && (
            <div className="relative w-full aspect-[16/9] md:aspect-[3/1] lg:aspect-[4/1] rounded-2xl overflow-hidden group cursor-pointer my-12 shadow-2xl border border-white/5">
                <img 
                  src={spotlightMovie.backdropUrl || spotlightMovie.thumbnailUrl} 
                  alt={spotlightMovie.title} 
                  className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                />
                <div className="absolute inset-0 bg-gradient-to-r from-black via-black/70 to-transparent"></div>
                <div className="absolute inset-0 flex flex-col justify-center px-8 md:px-16 max-w-3xl space-y-4">
                    <div className="flex items-center gap-3 animate-fade-in-up">
                        <span className="text-kada-pink font-bold tracking-widest text-[10px] uppercase border border-kada-pink/30 px-3 py-1 rounded-full bg-kada-pink/10 backdrop-blur-md">Movie of the Day</span>
                        <div className="flex gap-1">
                            {[1,2,3,4,5].map(i => <StarIcon key={i} className="w-3 h-3 text-kada-yellow" />)}
                        </div>
                    </div>
                    <h2 className="text-3xl md:text-5xl font-black text-white leading-tight drop-shadow-lg animate-fade-in-up" style={{animationDelay: '0.1s'}}>{spotlightMovie.title}</h2>
                    <p className="text-gray-300 line-clamp-2 md:text-lg animate-fade-in-up" style={{animationDelay: '0.2s'}}>{spotlightMovie.description}</p>
                    <div className="flex items-center gap-4 pt-4 animate-fade-in-up" style={{animationDelay: '0.3s'}}>
                        <Link to={`/watch/${spotlightMovie.id}`} className="px-8 py-3 bg-white text-black font-bold rounded-full hover:bg-gray-200 transition-transform hover:scale-105 flex items-center gap-2 shadow-[0_0_20px_rgba(255,255,255,0.4)]">
                            <PlayIcon className="w-5 h-5 fill-current" /> Watch Now
                        </Link>
                        <button className="p-3 rounded-full bg-white/10 backdrop-blur border border-white/30 hover:bg-white/20 hover:border-white text-white transition-colors">
                            <PlusIcon className="w-6 h-6" />
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Action & Adventure - Portrait Grid */}
        {actionMovies.length > 0 && (
            <section>
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 rounded-full bg-white/10 text-red-500"><FilmIcon className="w-5 h-5" /></div>
                    <h2 className="text-2xl font-bold text-white tracking-tight">Action & Adventure</h2>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-6 gap-4">
                    {actionMovies.map(item => (
                        <div key={item.id} className="transition-transform duration-300 hover:-translate-y-2">
                            <MediaCard item={item} variant="portrait" />
                        </div>
                    ))}
                </div>
            </section>
        )}

        {/* 3RD PARTY BUSINESS AD BANNER */}
        <div className="w-full h-32 md:h-40 rounded-xl overflow-hidden relative my-12 border border-white/5 group">
            <img src="https://picsum.photos/seed/ad/1200/200" className="w-full h-full object-cover opacity-60 group-hover:opacity-80 transition-opacity" />
            <div className="absolute inset-0 bg-gradient-to-r from-black via-black/50 to-transparent"></div>
            <div className="absolute inset-0 flex items-center justify-between p-8">
                <div>
                    <span className="text-xs font-bold text-gray-400 uppercase tracking-widest border border-gray-600 px-2 py-1 rounded mb-2 inline-block">Sponsored</span>
                    <h3 className="text-2xl font-bold text-white">Experience Future Tech</h3>
                    <p className="text-gray-300 text-sm">The latest gadgets for your smart home.</p>
                </div>
                <button className="bg-white text-black px-6 py-2 rounded-full font-bold hover:bg-gray-200 transition-colors">Shop Now</button>
            </div>
        </div>

        {/* Sci-Fi Dimensions - Stylized Grid */}
        {sciFiSeries.length > 0 && (
            <section>
                <div className="flex items-center gap-3 mb-6">
                    <div className="p-2 rounded-full bg-white/10 text-purple-500"><SparklesIcon className="w-5 h-5" /></div>
                    <h2 className="text-2xl font-bold text-white tracking-tight">Sci-Fi Dimensions</h2>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    {sciFiSeries.slice(0, 3).map((item, idx) => (
                        <div key={item.id} className={`group relative rounded-xl overflow-hidden ${idx === 0 ? 'md:col-span-2 aspect-[2/1]' : 'aspect-square'}`}>
