                   <h2 className="text-2xl font-bold text-white tracking-tight">{cat.title}</h2>
               </div>
               <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                 {cat.items.slice(0, 5).map(item => (
                   <MediaCard key={item.id} item={item} variant="portrait" />
                 ))}
               </div>
            </section>
        ))}

        {/* KIDS MODE AD */}
        <div className="relative w-full h-48 rounded-xl overflow-hidden mt-12 mb-20 border border-white/10 bg-gradient-to-r from-blue-500 to-teal-400">
             <div className="absolute inset-0 flex items-center p-8 md:p-12">
                 <div className="flex-1 text-white">
                     <h3 className="text-3xl font-black mb-2 uppercase tracking-tighter">Kada Kids</h3>
                     <p className="max-w-md font-medium">Safe, fun, and educational content for the little ones. Create a Kids Profile today.</p>
                 </div>
                 <div className="w-1/3 h-full relative hidden md:flex items-center justify-end pr-10">
                     <button className="bg-white text-blue-600 px-8 py-3 rounded-full font-bold shadow-xl hover:scale-105 transition-transform">Explore Kids</button>
                 </div>
             </div>
        </div>

      </div>

      {/* Custom CSS for Text Outline effect used in Top 10 */}
      <style>{`
        .font-outline-2 {
            -webkit-text-stroke: 2px rgba(255,255,255,0.2);
        }
        .text-kada-pink { color: #ff0080; }
        .text-kada-yellow { color: #ffcc00; }
        .perspective-1000 { perspective: 1000px; }
      `}</style>
    </div>
  );
};

export default Home;

export type MediaType = 'movie' | 'series';
export type AdType = 'preroll' | 'midroll' | 'postroll' | 'banner';
export type AdStatus = 'pending' | 'approved' | 'declined' | 'completed' | 'paused';

export interface Channel {
  id: string;
  name: string;
  logoUrl: string;
  streamUrl: string; // HLS/Dash stream
  currentProgram: string;
  category: string;
  viewers: number;
}

export interface Ad {
  id: string;
  videoUrl?: string; // Optional for banner ads
  imageUrl?: string; // For banner ads
  type: AdType;
  duration: number; // seconds
  startTime?: number; // seconds, for midroll or banner display start
  skipAfter?: number; // seconds
  linkUrl?: string;

  // Business Ad Fields
  isBusinessAd?: boolean;
  advertiserName?: string;
  budget?: number;
  status?: AdStatus;
  impressions?: number;
  clicks?: number;
  spent?: number;
  startDate?: number;
  endDate?: number;
}

export interface SubtitleTrack {
  id: string;
  label: string; // e.g. "English"
  language: string; // e.g. "en"
  src: string; // URL or Blob URL
}

export interface Episode {
  id: string;
  episodeNumber: number;
  title: string;
  description: string;
  thumbnailUrl: string;
  videoUrl: string;
  duration: string; // Display string "45m"
  releaseDate?: string;
  introStartTime?: number;
  introEndTime?: number;
}

export interface Season {
  id: string;
  seasonNumber: number;
  title: string;
  episodes: Episode[];
}

export interface Demographics {
  ageGroups: { range: string; percentage: number }[];
  topRegions: { country: string; percentage: number }[];
  genderSplit: { male: number; female: number; other: number };
}

export interface MediaAnalytics {
  views: number;
  uniqueViewers: number;
  listAdds: number;
  likes: number;
  completionRate: number; // 0-100
  totalWatchTime: number; // hours
  retentionCurve?: number[]; // Array of values 0-100 representing viewership over time
  demographics?: Demographics;
  revenueGenerated?: number; // Estimated revenue attribution
}

export interface MediaItem {
  id: string;
  type: MediaType;
  title: string;
  description: string;

  // Images
  thumbnailUrl: string; // Landscape (16:9)
  posterUrl: string;    // Portrait (2:3)
  backdropUrl: string;  // High Res Landscape

  // Metadata
  genre: string;
  year: number;
  releaseDate?: string;
  rating: string;
  studio?: string;
  cast: string[];
  crew: string[];
  tags: string[];

  // Media
  trailerUrl?: string;
  subtitles?: SubtitleTrack[];
  introStartTime?: number;
  introEndTime?: number;

  // Movie Specific
  videoUrl?: string;
  duration?: string;

  // Series Specific
  seasons?: Season[]; 

  // App Specific
  trending?: boolean;
  isComingSoon?: boolean;
  ads?: Ad[]; 

  // Geo Restrictions & Kids
  allowedCountries?: string[]; // If empty, allowed everywhere
  isKidsSafe?: boolean;

  // Metrics
  analytics?: MediaAnalytics;
}

export interface GeminiInsight {
  summary: string;
  keyTakeaways: string[];
  similarTopics: string[];
}

export enum LoadingState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

