}

export interface WatchHistoryItem {
  mediaId: string;
  episodeId?: string; // If series
  timestamp: number; // seconds watched
  lastWatchedAt: number; // Date.now()
  progress: number; // 0 to 1 (percentage)
}

export interface UserProfile {
  id: string;
  name: string;
  avatarUrl: string;
  isKids?: boolean;
  watchHistory: WatchHistoryItem[];
  myList: string[];
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  date: number;
  isRead: boolean;
  type: 'info' | 'success' | 'alert' | 'promo';
  link?: string;
}

export interface User {
  id: string;
  email: string;
  password?: string; // Simulation only
  planId: string;
  isAdmin?: boolean;
  profiles: UserProfile[];
  notifications?: Notification[];
}

export interface AppSettings {
  appName: string;
  appLogoText: string;
  appLogoHighlight: string;
  appIconUrl?: string;
  enableAdsGlobal: boolean;
  simulatedCountry: string; // For testing Geo-Blocking
  maintenanceMode: boolean;

  // Integrations
  paymentGateway?: 'paystack' | 'stripe' | 'none';
  paystackPublicKey?: string;
  smtpHost?: string;
  smtpPort?: number;
  adminEmail?: string;
}

export interface Genre {
  id: string;
  name: string;
}

import React, { useState, useRef, useEffect } from 'react';
import { PlayIcon, PauseIcon, VolumeHighIcon, VolumeMuteIcon, MaximizeIcon, SkipForwardIcon, CloseIcon, ListIcon, PhoneRotateIcon, SpeedIcon, QualityIcon, SubtitleIcon, ExternalLinkIcon, SettingsIcon } from './Icons';
import { Ad, SubtitleTrack } from '../types';

interface NextVideo {
  title: string;
  thumbnailUrl: string;
  subTitle?: string;
  onPlay: () => void;
}

interface RecommendedItem {
    id: string;
    title: string;
    thumbnailUrl: string;
    trailerUrl?: string;
    action: () => void;
}

interface VideoPlayerProps {
  src: string;
  poster?: string;
  title?: string;
  subTitle?: string;
  ads?: Ad[];
  nextVideo?: NextVideo | null;
  recommendedItem?: RecommendedItem | null;
  onEnded?: () => void;
  autoPlay?: boolean;
  startTime?: number; 
  isSeries?: boolean;
  onToggleEpisodes?: () => void;
  onClose?: () => void;
  onProgress?: (currentTime: number, duration: number) => void;
  initialSubtitles?: SubtitleTrack[];
  isLive?: boolean;
  introStartTime?: number;
  introEndTime?: number;
}

const PLAYBACK_SPEEDS = [0.5, 0.75, 1, 1.25, 1.5, 2];
const QUALITIES = ['Auto', '4K', '1080p', '720p', '480p'];

const VideoPlayer: React.FC<VideoPlayerProps> = ({ 
  src, poster, title, subTitle, ads = [], nextVideo, recommendedItem, onEnded, autoPlay = false, startTime = 0,
  isSeries, onToggleEpisodes, onClose, onProgress, initialSubtitles = [], isLive = false,
  introStartTime, introEndTime
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [isHovering, setIsHovering] = useState(false);
  const [playbackRate, setPlaybackRate] = useState(1);

  const [subtitles, setSubtitles] = useState<SubtitleTrack[]>(initialSubtitles);
  const [activeSubtitle, setActiveSubtitle] = useState<string | null>(null);
  const [showSubtitleMenu, setShowSubtitleMenu] = useState(false);

  const [showSpeedMenu, setShowSpeedMenu] = useState(false);
  const [showQualityMenu, setShowQualityMenu] = useState(false);
  const [activeQuality, setActiveQuality] = useState('Auto');

  const [showRecommendation, setShowRecommendation] = useState(false);

  const [adState, setAdState] = useState<'idle' | 'playing' | 'completed'>('idle');
  const [currentAd, setCurrentAd] = useState<Ad | null>(null);
  const [activeBannerAd, setActiveBannerAd] = useState<Ad | null>(null);
  const [adTimeLeft, setAdTimeLeft] = useState(0);
  const [canSkipAd, setCanSkipAd] = useState(false);
  const [playedAds, setPlayedAds] = useState<string[]>([]);
  const [showSkipRecap, setShowSkipRecap] = useState(false);
  const [showSkipIntro, setShowSkipIntro] = useState(false);

  useEffect(() => {
    setIsPlaying(false);
    setCurrentTime(0);
    setAdState('idle');
    setCurrentAd(null);
    setActiveBannerAd(null);
    setPlayedAds([]);
    setShowRecommendation(false);
    setSubtitles(initialSubtitles);
    setActiveSubtitle('off');
    setPlaybackRate(1);
    setActiveQuality('Auto');
    setShowSkipRecap(false);
    setShowSkipIntro(false);

    let seekTimeout: any;
    let playTimeout: any;

    if (videoRef.current) {
      // Ensure we don't carry over playback state confusingly
      videoRef.current.pause();

      seekTimeout = setTimeout(() => {
          if (videoRef.current && startTime > 0 && startTime < (videoRef.current.duration || Infinity) * 0.95) {
            videoRef.current.currentTime = startTime;
            setCurrentTime(startTime);
          }
      }, 100);
    }

    if (autoPlay && videoRef.current) {
      playTimeout = setTimeout(() => {
        if (videoRef.current) {
             const playPromise = videoRef.current.play();
             if (playPromise !== undefined) {
                 playPromise.catch(err => {
                     // Ignore AbortError (happens when element removed or src changed quickly)
                     if (err.name !== 'AbortError') {
                         console.log('Autoplay prevented', err);
                     }
                 });
             }
        }
      }, 500);
    }

    return () => {
        if (seekTimeout) clearTimeout(seekTimeout);
        if (playTimeout) clearTimeout(playTimeout);
    };
  }, [src]);

  const formatTime = (time: number) => {
    if (isNaN(time)) return "00:00";
    const hours = Math.floor(time / 3600);
    const minutes = Math.floor((time % 3600) / 60);
    const seconds = Math.floor(time % 60);

    if (hours > 0) {
        return `${hours}:${minutes < 10 ? '0' + minutes : minutes}:${seconds < 10 ? '0' + seconds : seconds}`;
    }
    return `${minutes}:${seconds < 10 ? '0' + seconds : seconds}`;
  };

  const checkForAds = (time: number) => {
    if (adState === 'playing') return;

    // Preroll
    // Ensure we trigger only if we are at the very start
    if (time < 0.5 && !playedAds.includes('preroll')) {
      const preroll = ads.find(a => a.type === 'preroll');
      if (preroll) {
        playAd(preroll, 'preroll');
        return;
      }
    }

    // Midroll
    const midrolls = ads.filter(a => a.type === 'midroll' && !playedAds.includes(a.id));
    for (const ad of midrolls) {
      if (ad.startTime && Math.abs(time - ad.startTime) < 1) {
        playAd(ad, ad.id);
        return;
      }
    }

    // Banner Ads Logic (Mocked frequency)
    if (!activeBannerAd && time > 60 && time % 300 < 1 && !playedAds.includes('banner-' + Math.floor(time))) {
        const banner = ads.find(a => a.type === 'banner');
        if (banner) {
            setActiveBannerAd(banner);
            setPlayedAds(prev => [...prev, 'banner-' + Math.floor(time)]);
            // Auto hide after 15s
            setTimeout(() => setActiveBannerAd(null), 15000);
        }
    }

    // Skip Recap Logic
    if (isSeries && time > 0 && time < 45 && !showSkipRecap && !showSkipIntro) {
        setShowSkipRecap(true);
    } else if ((time >= 45 || adState === 'playing') && showSkipRecap) {
        setShowSkipRecap(false);
    }

    // Skip Intro Logic
    if (introStartTime !== undefined && introEndTime !== undefined) {
        if (time >= introStartTime && time < introEndTime && !showSkipIntro && adState !== 'playing') {
            setShowSkipIntro(true);
        } else if ((time >= introEndTime || time < introStartTime || adState === 'playing') && showSkipIntro) {
            setShowSkipIntro(false);
        }
    }
  };

  const playAd = (ad: Ad, adIdToMark: string) => {
    if (!videoRef.current) return;
    videoRef.current.pause();
    setIsPlaying(false);
    setCurrentAd(ad);
    setAdState('playing');
    setAdTimeLeft(ad.duration);
    setCanSkipAd(false);
    setPlayedAds(prev => [...prev, adIdToMark]);
    if (ad.skipAfter && ad.skipAfter > 0) {
       setTimeout(() => setCanSkipAd(true), ad.skipAfter * 1000);
    }
  };

  const handleAdTick = () => {
    setAdTimeLeft(prev => {
      if (prev <= 1) {
        finishAd();
        return 0;
      }
      return prev - 1;
    });
  };

  useEffect(() => {
    let interval: any;
    if (adState === 'playing' && currentAd) {
      interval = setInterval(handleAdTick, 1000);
    }
    return () => clearInterval(interval);
  }, [adState, currentAd]);

  const finishAd = () => {
    // If it was a postroll, we are done with the content
    const wasPostroll = currentAd?.type === 'postroll';

    setAdState('idle');
    setCurrentAd(null);

    if (wasPostroll) {
       triggerEndSequence();
    } else {
       // Resume main video
       if (videoRef.current) {
         const p = videoRef.current.play();
         if (p !== undefined) {
             p.catch(e => { if (e.name !== 'AbortError') console.error("Resume error", e) });
         }
         setIsPlaying(true);
       }
    }
  };

  const skipRecap = () => {
      if (videoRef.current) {
          videoRef.current.currentTime = 45; // Jump to 45s
          setShowSkipRecap(false);
      }
  };

  const skipIntro = () => {
      if (videoRef.current && introEndTime) {
          videoRef.current.currentTime = introEndTime;
          setShowSkipIntro(false);
      }
  };

  const togglePlay = () => {
    if (adState === 'playing') return;
    if (showRecommendation) return; 

    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      const p = videoRef.current.play();
      if (p !== undefined) {
          p.catch(e => { if (e.name !== 'AbortError') console.error("Play error", e); });
      }
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const handleTimeUpdate = () => {
    if (!videoRef.current) return;
    const curr = videoRef.current.currentTime;
    const dur = videoRef.current.duration;
    setCurrentTime(curr);
    checkForAds(curr);

    if (onProgress && dur > 0) {
        onProgress(curr, dur);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const time = Number(e.target.value);
    videoRef.current.currentTime = time;
    setCurrentTime(time);
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    videoRef.current.muted = !isMuted;
    setIsMuted(!isMuted);
  };

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!videoRef.current) return;
    const vol = Number(e.target.value);
    videoRef.current.volume = vol;
    setVolume(vol);
    setIsMuted(vol === 0);
  };

  const changeSpeed = (speed: number) => {
    if (videoRef.current) {
        videoRef.current.playbackRate = speed;
        setPlaybackRate(speed);
        setShowSpeedMenu(false);
    }
  };

  const changeQuality = (q: string) => {
      setActiveQuality(q);
      setShowQualityMenu(false);
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen();
    } else {
      document.exitFullscreen();
    }
  };

  const triggerEndSequence = () => {
      if (nextVideo) {
        nextVideo.onPlay();
      } else if (recommendedItem) {
        setShowRecommendation(true);
      } else if (onEnded) {
        onEnded();
      }
  };

  const handleMainVideoEnded = () => {
    setIsPlaying(false);
    const postroll = ads.find(a => a.type === 'postroll' && !playedAds.includes('postroll'));
    if (postroll) {
      playAd(postroll, 'postroll');
    } else {
      triggerEndSequence();
    }
  };

  const changeSubtitle = (trackId: string) => {
      setActiveSubtitle(trackId);
      setShowSubtitleMenu(false);

      if (videoRef.current) {
          const tracks = videoRef.current.textTracks;
          for (let i = 0; i < tracks.length; i++) {
             const trackData = subtitles.find(s => s.id === trackId);

             if (trackId === 'off') {
                 tracks[i].mode = 'hidden';
             } else if (trackData && (tracks[i].label === trackData.label)) {
                 tracks[i].mode = 'showing';
             } else {
                 tracks[i].mode = 'hidden';
             }
          }
      }
  };

  const closeAllMenus = () => {
      setShowSpeedMenu(false);
      setShowQualityMenu(false);
      setShowSubtitleMenu(false);
  };

  useEffect(() => {
    let timeout: any;
    if (isHovering) {
      if (timeout) clearTimeout(timeout);
      timeout = setTimeout(() => {
        if (isPlaying && !showSpeedMenu && !showQualityMenu && !showSubtitleMenu) setIsHovering(false);
      }, 4000);
    }
    return () => clearTimeout(timeout);
  }, [isHovering, isPlaying, showSpeedMenu, showQualityMenu, showSubtitleMenu]);

  const showControls = !showRecommendation && adState !== 'playing' && (isHovering || !isPlaying || showSpeedMenu || showQualityMenu || showSubtitleMenu);

  return (
    <div 
      ref={containerRef}
      className="relative w-full h-full bg-black group overflow-hidden select-none font-sans"
      onMouseEnter={() => setIsHovering(true)}
      onMouseLeave={() => setIsHovering(false)}
      onMouseMove={() => setIsHovering(true)}
      onClick={closeAllMenus}
    >

      {/* Mobile Portrait Warning */}
      <div className="absolute inset-0 z-[60] bg-black flex-col items-center justify-center text-center p-10 hidden portrait:flex lg:portrait:hidden">
        <PhoneRotateIcon className="w-16 h-16 text-kada-pink mb-4 animate-bounce" />
        <h3 className="text-2xl font-bold text-white mb-2">Please Rotate Device</h3>
        <p className="text-gray-400">For the best cinematic experience, please switch to landscape mode.</p>
      </div>

      <video
        ref={videoRef}
        src={src}
        poster={poster}
        className="w-full h-full object-contain"
        onClick={(e) => { e.stopPropagation(); togglePlay(); }}
        onTimeUpdate={handleTimeUpdate}
        onLoadedMetadata={() => {
            if (videoRef.current) {
                setDuration(videoRef.current.duration || 0);
            }
        }}
        onEnded={handleMainVideoEnded}
        onPlay={() => setIsPlaying(true)}
        onPause={() => setIsPlaying(false)}
        crossOrigin="anonymous"
      >
          {subtitles.map((track, index) => (
              <track 
                 key={track.id}
                 kind="subtitles"
                 src={track.src}
                 srcLang={track.language}
                 label={track.label}
                 default={activeSubtitle === track.id}
              />
          ))}
      </video>

      {/* Top Overlay - Glass Gradient */}
      {showControls && (title || subTitle) && (
        <div className="absolute top-0 left-0 right-0 p-8 bg-gradient-to-b from-black/90 to-transparent z-40 pointer-events-none transition-opacity duration-500">
            <h2 className="text-white font-bold text-3xl drop-shadow-lg tracking-tight">{title}</h2>
            {subTitle && <p className="text-gray-200 text-base font-medium drop-shadow-md mt-1">{subTitle}</p>}
        </div>
      )}

      {/* Close Button - Floating Glass */}
      {showControls && onClose && (
        <button 
          onClick={onClose}
          className="absolute top-8 right-8 z-50 w-12 h-12 rounded-full glass-panel flex items-center justify-center text-white transition-all hover:bg-white/20 hover:scale-110 pointer-events-auto shadow-lg group/close"
          title="Exit Player"
        >
          <CloseIcon className="w-6 h-6 group-hover/close:rotate-90 transition-transform duration-300" />
        </button>
      )}

      {/* BANNER AD OVERLAY */}
      {activeBannerAd && (
          <div className="absolute bottom-32 left-1/2 -translate-x-1/2 z-[45] animate-fade-in-up">
              <div className="bg-black/80 backdrop-blur-md border border-white/20 p-4 rounded-xl shadow-2xl relative max-w-lg flex items-center gap-4">
                  <button onClick={(e) => { e.stopPropagation(); setActiveBannerAd(null); }} className="absolute -top-3 -right-3 bg-white text-black rounded-full p-1 shadow-lg hover:bg-gray-200">
                      <CloseIcon className="w-4 h-4" />
                  </button>
                  {activeBannerAd.imageUrl ? (
                      <img src={activeBannerAd.imageUrl} className="w-24 h-16 object-cover rounded" />
                  ) : (
                      <div className="w-24 h-16 bg-gray-700 rounded flex items-center justify-center text-xs text-gray-400">Ad Image</div>
                  )}
                  <div className="flex-1">
                      <h4 className="font-bold text-white text-sm">{activeBannerAd.advertiserName || 'Sponsored'}</h4>
                      <p className="text-xs text-gray-300 mb-2">Check out our latest offers today.</p>
                      {activeBannerAd.linkUrl && (
                          <a href={activeBannerAd.linkUrl} target="_blank" className="text-xs bg-kada-pink text-white px-3 py-1 rounded font-bold hover:bg-pink-600 inline-block">Learn More</a>
                      )}
                  </div>
              </div>
          </div>
      )}

      {/* SKIP RECAP BUTTON */}
      {showSkipRecap && !isLive && (
          <div className="absolute bottom-32 right-12 z-[45] animate-fade-in">
              <button 
                onClick={skipRecap}
                className="bg-white/10 backdrop-blur-md border border-white/30 text-white px-6 py-2 rounded-full font-bold hover:bg-white hover:text-black transition-all flex items-center gap-2 shadow-lg group"
              >
                  Skip Recap <SkipForwardIcon className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
              </button>
          </div>
      )}

      {/* SKIP INTRO BUTTON */}
      {showSkipIntro && !isLive && (
          <div className="absolute bottom-32 right-12 z-[45] animate-fade-in">
              <button 
                onClick={skipIntro}
                className="bg-white/10 backdrop-blur-md border border-white/30 text-white px-6 py-2 rounded-full font-bold hover:bg-white hover:text-black transition-all flex items-center gap-2 shadow-lg group"
              >
                  Skip Intro <SkipForwardIcon className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
              </button>
          </div>
      )}

      {/* AD OVERLAY */}
      {adState === 'playing' && currentAd && (
        <div className="absolute inset-0 z-50 bg-black flex flex-col items-center justify-center">
           <video 
             src={currentAd.videoUrl}
             autoPlay 
             className="absolute inset-0 w-full h-full object-contain"
           />

           <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-start pointer-events-auto">
                <div className="flex gap-2">
                    <span className="glass-panel text-white text-xs font-bold px-3 py-1.5 rounded-full border border-kada-yellow/50 text-kada-yellow uppercase tracking-wider">Ad</span>
                    {currentAd.advertiserName && (
                        <span className="glass-panel text-white text-xs font-bold px-3 py-1.5 rounded-full">
                            {currentAd.advertiserName}
                        </span>
                    )}
                </div>

                <div className="w-12 h-12 rounded-full glass-panel flex items-center justify-center border border-white/20 relative">
                    <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 36 36">
                        <path className="text-white/10" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="3" />
                        <path className="text-kada-yellow transition-all duration-1000 linear" strokeDasharray={`${(adTimeLeft / currentAd.duration) * 100}, 100`} d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="3" />
                    </svg>
                    <span className="text-sm font-bold text-white">{adTimeLeft}</span>
                </div>
           </div>

           <div className="absolute bottom-10 right-8 left-8 flex justify-between items-end pointer-events-auto z-50">
               <div>
                  {currentAd.linkUrl && (
                      <a href={currentAd.linkUrl} target="_blank" rel="noreferrer" className="flex items-center gap-2 glass-panel hover:bg-white/20 text-white px-6 py-3 rounded-full font-bold transition-all border border-white/20 group">
                          Visit Advertiser <ExternalLinkIcon className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                      </a>
                  )}
               </div>

              <div className="flex flex-col items-end space-y-4">
                  {canSkipAd ? (
                    <button onClick={finishAd} className="flex items-center gap-2 bg-white text-black px-8 py-3 rounded-full font-bold hover:scale-105 transition-all shadow-[0_0_20px_rgba(255,255,255,0.4)]">
                      Skip Ad <SkipForwardIcon className="w-5 h-5" />
                    </button>
                  ) : (
                    <div className="glass-panel px-6 py-3 rounded-full text-gray-300 text-sm font-medium border border-white/10">
                       Skip in <span className="text-white font-bold ml-1">{currentAd.skipAfter ? Math.max(0, currentAd.skipAfter - (currentAd.duration - adTimeLeft)) : adTimeLeft}s</span>
                    </div>
                  )}
              </div>
           </div>
        </div>
      )}

      {/* RECOMMENDATION OVERLAY */}
      {showRecommendation && recommendedItem && (
        <div className="absolute inset-0 z-50 bg-black flex flex-col items-center justify-center overflow-hidden animate-fade-in">
             {recommendedItem.trailerUrl && (
                 <div className="absolute inset-0 opacity-40">
                    <video src={recommendedItem.trailerUrl} autoPlay muted loop className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black via-black/60 to-black/80"></div>
                 </div>
             )}

             <div className="relative z-10 text-center p-8 max-w-4xl w-full">
                 <div className="text-kada-pink text-sm uppercase tracking-[0.3em] font-bold mb-6">Up Next</div>
                 <h2 className="text-5xl md:text-7xl font-black text-white mb-8 tracking-tight">{recommendedItem.title}</h2>

                 <div className="flex flex-col md:flex-row items-center justify-center gap-8 md:gap-12">
                     <div className="w-full max-w-sm aspect-video rounded-2xl overflow-hidden shadow-[0_0_40px_rgba(0,0,0,0.5)] relative border border-white/10 group cursor-pointer" onClick={() => recommendedItem.action()}>
                         <img src={recommendedItem.thumbnailUrl} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                         <div className="absolute inset-0 flex items-center justify-center">
                             <div className="w-16 h-16 rounded-full bg-white/20 backdrop-blur-md flex items-center justify-center border border-white/50 group-hover:scale-110 transition-transform">
                                 <PlayIcon className="w-8 h-8 text-white fill-white translate-x-0.5" />
                             </div>
                         </div>
                     </div>

                     <div className="flex flex-col gap-4 min-w-[200px]">
                         <button 
                            onClick={() => recommendedItem.action()}
                            className="px-8 py-4 bg-white text-black font-bold text-lg rounded-full hover:bg-gray-200 transition-all flex items-center justify-center gap-2 hover:scale-105 shadow-xl"
                         >
                             Play Now
                         </button>
                         <button 
                            onClick={onClose} 
                            className="px-8 py-4 glass-panel text-white font-bold text-lg rounded-full hover:bg-white/10 transition-all border border-white/20"
                         >
                             Cancel
                         </button>
                     </div>
                 </div>
             </div>
        </div>
      )}

      {/* CONTROLS BAR - Floating Glass Pill */}
      {showControls && (
        <div className="absolute bottom-8 left-4 right-4 md:left-12 md:right-12 z-40 animate-fade-in-up">
          <div className="bg-black/60 backdrop-blur-xl border border-white/10 rounded-2xl px-6 py-4 shadow-2xl relative">

              {/* Progress Bar - Floating above (Hidden for Live) */}
              {!isLive && (
                  <div className="absolute -top-3 left-4 right-4 group/progress h-1.5 cursor-pointer">
                     <div className="absolute inset-0 bg-white/20 rounded-full overflow-hidden backdrop-blur-sm">
                         <div 
                           className="h-full bg-gradient-to-r from-kada-pink to-kada-yellow rounded-full relative"
                           style={{ width: `${(currentTime / duration) * 100}%` }}
                         >
                            <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full shadow-[0_0_10px_rgba(255,255,255,0.8)] opacity-0 group-hover/progress:opacity-100 scale-0 group-hover/progress:scale-150 transition-all"></div>
                         </div>
                     </div>
                     <input 
                       type="range" 
                       min="0" 
                       max={duration || 100} 
                       value={currentTime} 
                       onChange={handleSeek}
                       onClick={(e) => e.stopPropagation()}
                       className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                     />
                  </div>
              )}

              <div className="flex items-center justify-between pt-2">
                {/* Left Controls */}
                <div className="flex items-center gap-6">
                   <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="text-white hover:text-kada-pink transition-colors hover:scale-110 transform">
                     {isPlaying ? <PauseIcon className="w-8 h-8" /> : <PlayIcon className="w-8 h-8 fill-current" />}
                   </button>

                   {!isLive && (
                       <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime -= 10; }} className="text-gray-300 hover:text-white transition-colors text-xs font-bold -ml-2">
                           -10s
                       </button>
                   )}

                   <div className="flex items-center gap-3 group/volume" onClick={(e) => e.stopPropagation()}>
                     <button onClick={toggleMute} className="text-gray-300 hover:text-white transition-colors">
                       {isMuted || volume === 0 ? <VolumeMuteIcon className="w-6 h-6" /> : <VolumeHighIcon className="w-6 h-6" />}
                     </button>
                     <div className="w-0 group-hover/volume:w-24 transition-all duration-300 overflow-hidden flex items-center">
                        <input 
                          type="range" 
                          min="0" 
                          max="1" 
                          step="0.1" 
                          value={isMuted ? 0 : volume}
                          onChange={handleVolumeChange}
                          className="w-20 h-1 bg-white/30 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:rounded-full hover:[&::-webkit-slider-thumb]:scale-110"
                        />
                     </div>
                   </div>

                   {!isLive ? (
                       <div className="text-xs font-bold text-gray-400 tracking-wider">
                         <span className="text-white">{formatTime(currentTime)}</span> / {formatTime(duration)}
                       </div>
                   ) : (
                       <div className="flex items-center gap-2">
                           <div className="w-2 h-2 rounded-full bg-red-600 animate-pulse"></div>
                           <span className="text-xs font-bold text-red-500 uppercase tracking-widest">Live</span>
                       </div>
                   )}
                </div>

                {/* Right Controls */}
                <div className="flex items-center gap-4 relative">

                   {/* Subtitles */}
                   <div className="relative">
                      <button onClick={(e) => { e.stopPropagation(); setShowSubtitleMenu(!showSubtitleMenu); setShowSpeedMenu(false); setShowQualityMenu(false); }} className={`hover:text-white transition-colors hover:scale-110 ${activeSubtitle && activeSubtitle !== 'off' ? 'text-kada-pink' : 'text-gray-300'}`}>
                         <SubtitleIcon className="w-5 h-5" />
                      </button>
                      {showSubtitleMenu && (
                          <div className="absolute bottom-full mb-6 left-1/2 -translate-x-1/2 bg-black/90 backdrop-blur-xl border border-white/10 rounded-xl py-2 min-w-[180px] shadow-2xl overflow-hidden z-50 animate-fade-in-up origin-bottom">
                              <div className="px-4 py-2 text-[10px] font-bold text-gray-500 uppercase tracking-wider border-b border-white/10 mb-1">Subtitles</div>
                              <button onClick={(e) => { e.stopPropagation(); changeSubtitle('off'); }} className={`block w-full text-left px-4 py-2 text-sm hover:bg-white/10 transition-colors ${activeSubtitle === 'off' ? 'text-kada-pink font-bold' : 'text-gray-300'}`}>Off</button>
                              {subtitles.map(track => (
                                  <button key={track.id} onClick={(e) => { e.stopPropagation(); changeSubtitle(track.id); }} className={`block w-full text-left px-4 py-2 text-sm hover:bg-white/10 transition-colors ${activeSubtitle === track.id ? 'text-kada-pink font-bold' : 'text-gray-300'}`}>{track.label}</button>
                              ))}
                          </div>
                      )}
                   </div>

                   {/* Settings (Quality & Speed) */}
                   {!isLive && (
                       <div className="relative group/settings">
                            <button className="text-gray-300 hover:text-white transition-colors hover:scale-110 hover:rotate-45 duration-300">
                                <SettingsIcon className="w-5 h-5" />
                            </button>
                            <div className="absolute bottom-full mb-6 right-0 bg-black/90 backdrop-blur-xl border border-white/10 rounded-xl p-2 min-w-[200px] shadow-2xl overflow-hidden z-50 hidden group-hover/settings:block animate-fade-in-up origin-bottom-right">
                                {/* Quality Section */}
                                <div className="px-3 py-2">
                                    <div className="text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Quality</div>
                                    <div className="flex flex-wrap gap-2">
                                        {QUALITIES.map(q => (
                                            <button key={q} onClick={() => changeQuality(q)} className={`px-2 py-1 rounded text-xs font-bold transition-colors ${activeQuality === q ? 'bg-kada-pink text-white' : 'bg-white/10 text-gray-400 hover:text-white'}`}>{q}</button>
                                        ))}
                                    </div>
                                </div>
                                <div className="h-px bg-white/10 my-1"></div>
                                {/* Speed Section */}
                                <div className="px-3 py-2">
                                    <div className="text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Speed</div>
                                    <div className="flex flex-wrap gap-2">
                                        {PLAYBACK_SPEEDS.map(s => (
                                            <button key={s} onClick={() => changeSpeed(s)} className={`px-2 py-1 rounded text-xs font-bold transition-colors ${playbackRate === s ? 'bg-kada-pink text-white' : 'bg-white/10 text-gray-400 hover:text-white'}`}>{s}x</button>
                                        ))}
                                    </div>
                                </div>
                            </div>
                       </div>
                   )}

                   {/* Next Episode Button */}
                   {nextVideo && (
                     <button 
                        onClick={(e) => { e.stopPropagation(); nextVideo.onPlay(); }} 
                        className="flex items-center gap-2 bg-white/10 hover:bg-white/20 text-white rounded-full px-4 py-1.5 transition-colors border border-white/10"
                        title="Next Episode"
                     >
                       <span className="text-xs font-bold">Next Ep</span>
                       <SkipForwardIcon className="w-4 h-4" />
                     </button>
                   )}

                   {(isSeries || isLive) && onToggleEpisodes && (
                     <button onClick={(e) => { e.stopPropagation(); onToggleEpisodes(); }} className="text-gray-300 hover:text-white transition-colors hover:scale-110">
                       <ListIcon className="w-5 h-5" />
                     </button>
                   )}

                   <button onClick={(e) => { e.stopPropagation(); toggleFullscreen(); }} className="text-gray-300 hover:text-white transition-colors hover:scale-110 ml-2">
                     <MaximizeIcon className="w-5 h-5" />
                   </button>
                </div>
              </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default VideoPlayer;

import React, { useEffect, useState, useMemo } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { store } from '../store';
import { MediaItem, Episode, Channel } from '../types';
import { CloseIcon, TvIcon } from '../components/Icons';
import VideoPlayer from '../components/VideoPlayer';

const Player: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const [media, setMedia] = useState<MediaItem | null>(null);
  const [library, setLibrary] = useState<MediaItem[]>(store.getLibrary());
  const [channels, setChannels] = useState<Channel[]>(store.getChannels());

  const [currentEpisode, setCurrentEpisode] = useState<Episode | null>(null);
  const [showSidePanel, setShowSidePanel] = useState(false);
  const [isLiveContent, setIsLiveContent] = useState(false);

  useEffect(() => {
    // 1. Try to find in regular Library
    let found = library.find(m => m.id === id);
    let isChannel = false;

    // 2. If not found, check Channels
    if (!found) {
        const channel = channels.find(c => c.id === id);
        if (channel) {
            isChannel = true;
            // Construct a mock MediaItem for the player
            found = {
                id: channel.id,
                title: channel.name,
                description: `Live Stream: ${channel.currentProgram}`,
                type: 'movie', // Treat as single video for basic structure
                thumbnailUrl: channel.logoUrl,
                posterUrl: channel.logoUrl,
                backdropUrl: channel.logoUrl,
                videoUrl: channel.streamUrl,
                genre: channel.category,
                year: new Date().getFullYear(),
                rating: 'TV-PG',
                studio: 'Kada Live',
                cast: [],
                crew: [],
                tags: ['Live TV', channel.category],
                analytics: { 
                    views: channel.viewers,
                    uniqueViewers: 0, listAdds: 0, likes: 0, completionRate: 0, totalWatchTime: 0
                }
            } as MediaItem;
        }
    }

    if (found) {
      setMedia(found);
      setIsLiveContent(isChannel);

      const startEpId = (location.state as any)?.startEpisodeId;
      if (found.type === 'series' && found.seasons && !isChannel) {
        if (startEpId) {
           for (const s of found.seasons) {
             const ep = s.episodes.find(e => e.id === startEpId);
             if (ep) { setCurrentEpisode(ep); return; }
           }
        }
        const profile = store.getCurrentProfile();
        const lastWatchedEp = profile.watchHistory.find(h => h.mediaId === found.id)?.episodeId;
        if (lastWatchedEp) {
           for (const s of found.seasons) {
             const ep = s.episodes.find(e => e.id === lastWatchedEp);
             if (ep) { setCurrentEpisode(ep); return; }
           }
        }
        if (!currentEpisode) setCurrentEpisode(found.seasons[0]?.episodes[0]);
      } else {
        setCurrentEpisode(null);
      }
    }
  }, [id, library, channels]);

  useEffect(() => {
     setShowSidePanel(false);
  }, [currentEpisode, media]);

  const nextEpisodeData = useMemo(() => {
    if (isLiveContent || !media || media.type !== 'series' || !media.seasons || !currentEpisode) return null;
    let currentSeasonIndex = -1;
    let currentEpIndex = -1;

    media.seasons.forEach((season, sIdx) => {
      const epIdx = season.episodes.findIndex(e => e.id === currentEpisode.id);
      if (epIdx !== -1) { currentSeasonIndex = sIdx; currentEpIndex = epIdx; }
    });

    if (currentSeasonIndex === -1) return null;
    const currentSeason = media.seasons[currentSeasonIndex];
    if (currentEpIndex < currentSeason.episodes.length - 1) {
      return { episode: currentSeason.episodes[currentEpIndex + 1], season: currentSeason };
    }
    if (currentSeasonIndex < media.seasons.length - 1) {
      const nextSeason = media.seasons[currentSeasonIndex + 1];
      if (nextSeason.episodes.length > 0) return { episode: nextSeason.episodes[0], season: nextSeason };
    }
    return null;
  }, [media, currentEpisode, isLiveContent]);

  const recommendedItem = useMemo(() => {
     if (!media || isLiveContent) return null; // No auto-rec for live yet
     const candidates = library.filter(m => m.genre === media.genre && m.id !== media.id);
     const rec = candidates.length > 0 ? candidates[Math.floor(Math.random() * candidates.length)] : library.find(m => m.id !== media.id);
     if (rec) {
         return {
             id: rec.id, title: rec.title, thumbnailUrl: rec.backdropUrl || rec.thumbnailUrl, trailerUrl: rec.trailerUrl,
             action: () => { navigate(`/watch/${rec.id}`); }
         }
     }
     return null;
  }, [media, library, isLiveContent]);

  const handleNext = () => {
    if (nextEpisodeData) { setCurrentEpisode(nextEpisodeData.episode); }
  };

  const handleClosePlayer = () => {
      if (isLiveContent) {
          navigate('/live');
      } else {
          navigate(`/title/${media?.id}`);
      }
  };

  const handleProgress = (time: number, duration: number) => {
      if (!media || isLiveContent) return;
      if (Math.floor(time) % 5 === 0) {
        store.updateWatchHistory(media.id, time, duration, currentEpisode?.id);
      }
  };

  const getStartTime = () => {
      if (!media || isLiveContent) return 0;
      const profile = store.getCurrentProfile();
      const historyItem = profile.watchHistory.find(h => h.mediaId === media.id && (currentEpisode ? h.episodeId === currentEpisode.id : true));
      if (historyItem) {
          if (historyItem.progress > 0.95) return 0;
          return historyItem.timestamp;
      }
      return 0;
  };

  if (!media) return <div className="h-screen bg-black flex items-center justify-center text-white">Loading...</div>;

  const videoSource = currentEpisode ? currentEpisode.videoUrl : media.videoUrl;
  const posterSource = currentEpisode ? currentEpisode.thumbnailUrl : media.thumbnailUrl;
  const displayTitle = media.title;
  const subTitle = isLiveContent 
        ? media.description.replace('Live Stream: ', '') 
        : currentEpisode 
            ? `S${media.seasons?.find(s => s.episodes.includes(currentEpisode!))?.seasonNumber} E${currentEpisode.episodeNumber}: ${currentEpisode.title}` 
            : undefined;

  const startTime = getStartTime();

  // Extract intro timestamps from current episode OR media item
  const introStartTime = currentEpisode?.introStartTime ?? media.introStartTime;
  const introEndTime = currentEpisode?.introEndTime ?? media.introEndTime;

  const nextVideoProp = nextEpisodeData ? {
    title: nextEpisodeData.episode.title,
    thumbnailUrl: nextEpisodeData.episode.thumbnailUrl,
    subTitle: `S${nextEpisodeData.season.seasonNumber} E${nextEpisodeData.episode.episodeNumber}`,
    onPlay: handleNext
  } : null;

  return (
    <div className="fixed inset-0 z-50 bg-black overflow-hidden font-sans">
       <VideoPlayer 
          key={videoSource}
          src={videoSource || ''} poster={posterSource} title={displayTitle} subTitle={subTitle} ads={media.ads}
          autoPlay={true} startTime={startTime} nextVideo={nextVideoProp} recommendedItem={recommendedItem}
          onEnded={handleNext} 
          isSeries={media.type === 'series'}
          isLive={isLiveContent}
          onToggleEpisodes={() => { setShowSidePanel(!showSidePanel); }}
          onClose={handleClosePlayer} onProgress={handleProgress}
          introStartTime={introStartTime}
          introEndTime={introEndTime}
       />

       {/* SIDE PANEL (Episodes OR Channels) */}
       <div className={`absolute top-0 right-0 h-full w-80 md:w-96 bg-zinc-900/95 border-l border-white/10 transform transition-transform duration-300 ease-in-out z-[60] ${showSidePanel ? 'translate-x-0' : 'translate-x-full'}`}>
           <div className="p-6 h-full flex flex-col">
               <div className="flex items-center justify-between mb-6 border-b border-white/10 pb-4">
                   <h2 className="text-white font-bold text-xl">{isLiveContent ? 'Live Channels' : 'Episodes'}</h2>
                   <button onClick={() => setShowSidePanel(false)} className="text-gray-400 hover:text-white"><CloseIcon className="w-6 h-6" /></button>
               </div>

               <div className="flex-1 overflow-y-auto no-scrollbar space-y-6">

                   {/* SERIES EPISODES LIST */}
                   {!isLiveContent && media.seasons?.map(season => (
                       <div key={season.id}>
                           <h3 className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-3 sticky top-0 bg-zinc-900 py-2 z-10">Season {season.seasonNumber}</h3>
                           <div className="space-y-1">
                               {season.episodes.map(ep => {
                                   const isActive = currentEpisode?.id === ep.id;
                                   return (
                                       <div 
                                         key={ep.id} onClick={() => setCurrentEpisode(ep)}
                                         className={`flex gap-3 p-3 rounded hover:bg-white/10 cursor-pointer transition-colors ${isActive ? 'bg-white/10' : ''}`}
                                       >
                                           <div className="text-gray-500 font-bold text-lg self-center w-6">{ep.episodeNumber}</div>
                                           <div className="relative w-24 h-14 rounded overflow-hidden bg-zinc-800 flex-shrink-0">
                                               <img src={ep.thumbnailUrl} className="w-full h-full object-cover" alt="" />
                                               {isActive && <div className="absolute inset-0 bg-black/40 flex items-center justify-center"><div className="w-2 h-2 bg-utv-500 rounded-full animate-ping"></div></div>}
                                           </div>
                                           <div className="min-w-0 flex flex-col justify-center">
                                               <h4 className={`text-sm font-bold truncate ${isActive ? 'text-white' : 'text-gray-300'}`}>{ep.title}</h4>
                                               <p className="text-xs text-gray-500">{ep.duration}</p>
                                           </div>
                                       </div>
                                   )
                               })}
                           </div>
                       </div>
                   ))}

                   {/* LIVE CHANNELS LIST */}
                   {isLiveContent && (
                       <div className="space-y-4">
                           <div>
                               <h3 className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-3">Up Next</h3>
                               <div className="bg-white/5 rounded-lg p-3 space-y-2">
                                   <div className="flex justify-between text-sm"><span className="text-white">14:00</span><span className="text-gray-400">News Update</span></div>
                                   <div className="flex justify-between text-sm"><span className="text-white">15:30</span><span className="text-gray-400">Documentary</span></div>
                                   <div className="flex justify-between text-sm"><span className="text-white">17:00</span><span className="text-gray-400">Music Hour</span></div>
                               </div>
                           </div>

                           <div>
                               <h3 className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-3">Other Channels</h3>
                               <div className="space-y-2">
                                   {channels.filter(c => c.id !== media.id).map(c => (
                                       <button 
                                            key={c.id}
                                            onClick={() => { navigate(`/watch/${c.id}`); setShowSidePanel(false); }}
                                            className="w-full flex items-center gap-3 p-3 rounded-lg hover:bg-white/10 transition-colors text-left group"
                                       >
                                           <div className="w-10 h-10 bg-white rounded flex items-center justify-center p-1 shrink-0">
                                               <img src={c.logoUrl} className="max-w-full max-h-full object-contain" />
                                           </div>
                                           <div className="min-w-0">
                                               <h4 className="text-sm font-bold text-gray-300 group-hover:text-white truncate">{c.name}</h4>
                                               <p className="text-xs text-gray-500 truncate">{c.category}</p>
                                           </div>
                                       </button>
                                   ))}
                               </div>
                           </div>
                       </div>
                   )}

               </div>
           </div>
       </div>
    </div>
  );
};

export default Player;

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { HomeIcon, SearchIcon, DashboardIcon, UserIcon, CalendarIcon, BellIcon, CheckIcon, CloseIcon, TvIcon } from './Icons';
import { store } from '../store';
import { AppSettings, User, UserProfile, Notification } from '../types';

interface LayoutProps {
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ children }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [scrolled, setScrolled] = useState(false);
  const [settings, setSettings] = useState<AppSettings>(store.getSettings());
  const [user, setUser] = useState<User>(store.getUser());
  const [currentProfile, setCurrentProfile] = useState<UserProfile>(store.getCurrentProfile());

  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const isLanding = location.pathname === '/';
  const isPlayer = location.pathname.startsWith('/watch');
  const isAdmin = location.pathname.startsWith('/admin');
  const isProfileSelect = location.pathname === '/profiles';
  const isAuthPage = location.pathname === '/login' || location.pathname === '/signup';

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);

    const updateData = () => {
        setSettings(store.getSettings());
        const u = store.getUser();
        setUser(u);
        setCurrentProfile(store.getCurrentProfile());
        setNotifications(u.notifications || []);
    };

    updateData();

    const unsubSettings = store.subscribe('settings', updateData);
    const unsubUser = store.subscribe('user', updateData);
    const unsubProfile = store.subscribe('profile', updateData);

    return () => {
      window.removeEventListener('scroll', handleScroll);
      unsubSettings();
      unsubUser();
      unsubProfile();
    };
  }, []);

  useEffect(() => {
      if (!isLanding && !isProfileSelect && !isAuthPage && !store.getActiveProfileId() && user.id) {
          navigate('/profiles');
      }
  }, [location.pathname, user.id]);

  const handleProfileSwitch = (profileId: string) => {
      store.setActiveProfileId(profileId);
      setShowProfileMenu(false);
      navigate('/app');
  };

  const handleMarkRead = (id: string) => {
      store.markNotificationRead(id);
  };

  const handleMarkAllRead = () => {
      store.markAllNotificationsRead();
  };

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const isActive = (path: string) => location.pathname === path ? 'text-kada-pink font-bold' : 'text-gray-300 hover:text-white';

  if (isProfileSelect || isAuthPage) {
      return <>{children}</>;
  }

  return (
    <div className="min-h-screen bg-kada-dark text-white font-sans selection:bg-kada-pink selection:text-white relative overflow-x-hidden">

      {/* Ambient Background Gradient Mesh */}
      {!isPlayer && (
        <div className="fixed inset-0 z-0 pointer-events-none opacity-20">
          <div className="absolute top-[-10%] left-[-10%] w-[50vw] h-[50vw] bg-kada-pink rounded-full blur-[150px] animate-float"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[40vw] h-[40vw] bg-kada-yellow rounded-full blur-[150px] animate-pulse-slow"></div>
        </div>
      )}

      {!isPlayer && !isAdmin && (
        <div className={`fixed top-4 left-0 right-0 z-50 flex justify-center transition-all duration-500 ${scrolled ? 'translate-y-0' : 'translate-y-2'}`}>
          <nav className="glass-panel px-6 py-3 rounded-full flex items-center gap-8 shadow-2xl transition-all duration-300 max-w-5xl w-[95%] sm:w-auto">

            <Link to={isLanding ? '/' : '/app'} className="flex items-center gap-1 group">
              <span className="text-2xl font-black tracking-tighter text-white">
                {settings.appLogoText}<span className="text-transparent bg-clip-text bg-gradient-to-r from-kada-pink to-kada-yellow">{settings.appLogoHighlight}</span>
              </span>
            </Link>

            {!isLanding && (
              <div className="hidden md:flex items-center space-x-6 border-l border-white/10 pl-6 h-6">
                <Link to="/app" className={`text-sm transition-colors ${isActive('/app')}`}>Home</Link>
                <Link to="/browse" className={`text-sm transition-colors ${isActive('/browse')}`}>Explore</Link>
                <Link to="/live" className={`text-sm transition-colors flex items-center gap-1 ${isActive('/live')}`}>
                    <div className="w-1.5 h-1.5 rounded-full bg-red-500 animate-pulse"></div> Live TV
                </Link>
                <Link to="/coming-soon" className={`text-sm transition-colors ${isActive('/coming-soon')}`}>New</Link>
                {user.isAdmin && (
                   <Link to="/admin" className={`text-sm transition-colors ${location.pathname.startsWith('/admin') ? 'text-kada-yellow font-bold' : 'text-gray-300 hover:text-white'}`}>Admin</Link>
                )}
              </div>
            )}

            <div className="flex-1"></div>

            <div className="flex items-center gap-5">
              {isLanding ? (
                 <div className="flex items-center gap-3">
                     <Link to="/login" className="text-sm font-semibold hover:text-kada-pink transition-colors">Log In</Link>
                     <Link to="/signup" className="px-5 py-2 bg-gradient-to-r from-kada-pink to-kada-yellow text-black font-bold text-sm rounded-full hover:shadow-lg hover:shadow-kada-pink/30 transition-all">
                        Join
                     </Link>
                 </div>
              ) : (
                <div className="flex items-center gap-5">
                    <Link to="/browse" className="text-white hover:text-kada-pink transition-colors"><SearchIcon className="w-5 h-5" /></Link>

                    {/* NOTIFICATIONS */}
                    <div className="relative">
                        <button 
                            onClick={() => { setShowNotifications(!showNotifications); setShowProfileMenu(false); }}
                            className="relative text-white hover:text-kada-yellow transition-colors"
                        >
                            <BellIcon className="w-5 h-5" />
                            {unreadCount > 0 && (
                                <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-kada-pink rounded-full border-2 border-black"></span>
                            )}
                        </button>

                        {showNotifications && (
                            <div className="absolute top-full right-[-60px] md:right-0 mt-6 w-80 glass-panel rounded-2xl overflow-hidden z-50 animate-fade-in origin-top-right">
                                <div className="p-4 border-b border-white/10 flex justify-between items-center bg-black/20">
                                    <span className="font-bold text-sm text-white">Notifications</span>
                                    {unreadCount > 0 && (
                                        <button onClick={handleMarkAllRead} className="text-xs text-kada-pink hover:underline">Mark all read</button>
                                    )}
                                </div>
                                <div className="max-h-[300px] overflow-y-auto custom-scrollbar">
                                    {notifications.length === 0 ? (
                                        <div className="p-6 text-center text-gray-400 text-sm">All caught up!</div>
                                    ) : (
                                        notifications.map(notif => (
                                            <div 
                                                key={notif.id} 
                                                onClick={() => handleMarkRead(notif.id)}
                                                className={`p-4 border-b border-white/5 hover:bg-white/5 transition-colors cursor-pointer relative ${!notif.isRead ? 'bg-white/5' : ''}`}
                                            >
                                                {!notif.isRead && <div className="absolute left-0 top-0 bottom-0 w-1 bg-kada-pink"></div>}
                                                <h4 className={`text-sm font-bold mb-1 ${!notif.isRead ? 'text-white' : 'text-gray-400'}`}>{notif.title}</h4>
                                                <p className="text-xs text-gray-500 leading-relaxed">{notif.message}</p>
                                            </div>
                                        ))
                                    )}
                                </div>
                            </div>
                        )}
                    </div>

                    {/* PROFILE */}
                    <div className="relative group">
                        <button 
                            onClick={() => { setShowProfileMenu(!showProfileMenu); setShowNotifications(false); }}
                            className="flex items-center gap-2"
                        >
                            <div className="w-9 h-9 rounded-full bg-zinc-800 p-[2px] bg-gradient-to-tr from-kada-pink to-kada-yellow">
                                <img src={currentProfile.avatarUrl || 'https://picsum.photos/200'} alt={currentProfile.name} className="w-full h-full rounded-full object-cover border-2 border-black" />
                            </div>
                        </button>

                        {showProfileMenu && (
                            <div className="absolute top-full right-0 mt-6 w-56 glass-panel rounded-2xl overflow-hidden z-50 animate-fade-in origin-top-right">
                                <div className="p-3 border-b border-white/10">
                                    {user.profiles.map(p => (
                                        <button 
                                            key={p.id}
                                            onClick={() => handleProfileSwitch(p.id)}
                                            className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg hover:bg-white/10 transition-colors ${p.id === currentProfile.id ? 'bg-white/10' : ''}`}
                                        >
                                            <img src={p.avatarUrl} className="w-8 h-8 rounded-full object-cover" />
                                            <span className={`text-sm ${p.id === currentProfile.id ? 'font-bold text-white' : 'text-gray-400'}`}>{p.name}</span>
                                        </button>
                                    ))}
                                    <Link to="/profiles" className="w-full text-left text-xs text-kada-yellow hover:underline px-3 py-2 mt-2 block">Manage Profiles</Link>
                                </div>
                                <div className="p-2 space-y-1">
                                    <Link to="/profile" className="block px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/5 rounded-lg" onClick={() => setShowProfileMenu(false)}>Account</Link>
                                    <button onClick={() => { store.logout(); navigate('/'); }} className="w-full text-left block px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/5 rounded-lg">Sign Out</button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
              )}
            </div>
          </nav>
        </div>
      )}

      {/* Mobile Bottom Navigation */}
      {!isLanding && !isPlayer && !isAdmin && (
        <div className="md:hidden fixed bottom-6 left-6 right-6 z-50">
           <div className="glass-panel rounded-2xl flex justify-around items-center p-3 shadow-2xl">
              <Link to="/app" className={`flex flex-col items-center p-2 rounded-lg transition-colors ${location.pathname === '/app' ? 'text-kada-pink bg-white/10' : 'text-gray-400'}`}>
                <HomeIcon className="w-6 h-6" />
              </Link>
              <Link to="/browse" className={`flex flex-col items-center p-2 rounded-lg transition-colors ${location.pathname === '/browse' ? 'text-kada-pink bg-white/10' : 'text-gray-400'}`}>
                <SearchIcon className="w-6 h-6" />
              </Link>
              <Link to="/live" className={`flex flex-col items-center p-2 rounded-lg transition-colors ${location.pathname === '/live' ? 'text-kada-pink bg-white/10' : 'text-gray-400'}`}>
                <TvIcon className="w-6 h-6" />
              </Link>
              <Link to="/coming-soon" className={`flex flex-col items-center p-2 rounded-lg transition-colors ${location.pathname === '/coming-soon' ? 'text-kada-pink bg-white/10' : 'text-gray-400'}`}>
                <CalendarIcon className="w-6 h-6" />
              </Link>
              <Link to="/profile" className={`flex flex-col items-center p-2 rounded-lg transition-colors ${location.pathname === '/profile' ? 'text-kada-pink bg-white/10' : 'text-gray-400'}`}>
                <UserIcon className="w-6 h-6" />
              </Link>
           </div>
        </div>
      )}

      {/* Main Content */}
      <main className="relative z-10">
        {children}
      </main>

      {/* Footer */}
      {!isPlayer && !isAdmin && !isAuthPage && (
        <footer className="border-t border-white/5 bg-black py-16 relative z-10 mb-20 md:mb-0">
          <div className="container mx-auto px-6 max-w-5xl">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8 text-sm text-gray-500">
              <ul className="space-y-4">
                  <li><Link to="/app" className="hover:text-kada-pink transition-colors">Home</Link></li>
                  <li><Link to="/browse" className="hover:text-kada-pink transition-colors">Browse</Link></li>
                  <li><Link to="/coming-soon" className="hover:text-kada-pink transition-colors">Coming Soon</Link></li>
              </ul>
              <ul className="space-y-4">
                  <li><Link to="/profile" className="hover:text-kada-pink transition-colors">Account</Link></li>
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Help Center</a></li>
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Terms of Use</a></li>
              </ul>
              <ul className="space-y-4">
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Privacy</a></li>
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Cookie Preferences</a></li>
                  <li><a href="#" className="hover:text-kada-pink transition-colors">Corporate Info</a></li>
                  <li><Link to="/business" className="hover:text-kada-pink transition-colors">Advertising</Link></li>
                  <li><Link to="/admin" className="hover:text-kada-pink transition-colors">Admin Panel</Link></li>
              </ul>
              <div className="space-y-4">
                  <h4 className="text-white font-bold">Connect</h4>
                  <div className="flex gap-4">
                      <div className="w-8 h-8 rounded-full bg-white/10 hover:bg-kada-pink transition-colors cursor-pointer"></div>
                      <div className="w-8 h-8 rounded-full bg-white/10 hover:bg-kada-yellow transition-colors cursor-pointer"></div>
                      <div className="w-8 h-8 rounded-full bg-white/10 hover:bg-white transition-colors cursor-pointer"></div>
                  </div>
                  <p className="text-xs pt-4">© 2024 Kada+ Nigeria</p>
              </div>
            </div>
          </div>
        </footer>
      )}
    </div>
  );
};

export default Layout;
